          <label
            key={col.id}
            className="flex cursor-pointer items-center gap-2 rounded px-2 py-1 hover:bg-muted/50"
          >
            <Checkbox
              checked={col.getIsVisible()}
              onCheckedChange={() => col.toggleVisibility()}
            />
            <span className="text-sm">{getColumnHeaderText(col)}</span>
