// ─── Refresh Button ──────────────────────────────────────────────────────────

const RefreshButton = memo(function RefreshButton() {
  const { isRefetching, onRefresh } = useDataGridContext()

  if (!onRefresh) return null

  return (
    <Button
      variant="ghost"
      size="icon"
      className="h-8 w-8"
      onClick={onRefresh}
      disabled={isRefetching}
      title="Refresh"
    >
      <RefreshCw
        className={cn("h-3.5 w-3.5", isRefetching && "animate-spin")}
      />
    </Button>
  )
})

// ─── Export CSV ──────────────────────────────────────────────────────────────

const ExportButton = memo(function ExportButton() {
  const { table } = useDataGridContext()

  const handleExport = () => {
    const rows = table
      .getFilteredRowModel()
      .rows.map((r) => r.original) as GridRow[]
    const columns = table
      .getVisibleLeafColumns()
      .map((col) => col.columnDef) as GridColumnDef[]
    exportToCsv(rows, columns, "export")
  }

  return (
    <Button
      variant="ghost"
      size="sm"
      className="h-8 gap-1.5"
      onClick={handleExport}
    >
      <Download className="h-3.5 w-3.5" />
      <span className="text-xs">Export</span>
    </Button>
  )
})

// ─── Add Row ──────────────────────────────────────────────────────────────────

const AddRowButton = memo(function AddRowButton() {
  const { features } = useDataGridContext()
  const addRowConfig =
    typeof features?.addRow === "object" ? features.addRow : null
  const onAddRow = addRowConfig?.onAddRow

  if (!features?.addRow) return null

  return (
    <Button size="sm" className="h-8 gap-1.5" onClick={onAddRow}>
      <Plus className="h-3.5 w-3.5" />
      <span className="text-xs">Add row</span>
    </Button>
  )
})

// ─── Selection Action Bar ────────────────────────────────────────────────────

const SelectionActionBar = memo(function SelectionActionBar() {
  const { table, slots } = useDataGridContext()
  const selectedRows = table
    .getSelectedRowModel()
    .rows.map((r) => r.original) as GridRow[]

  if (selectedRows.length === 0) return null

  const handleExportSelected = () => {
    const columns = table
      .getVisibleLeafColumns()
      .map((col) => col.columnDef) as GridColumnDef[]
    exportToCsv(selectedRows, columns, "selected-export")
  }

  const clearSelection = () => table.resetRowSelection()

  return (
    <div className="flex h-10 animate-in items-center gap-2 border-b border-primary/20 bg-primary/5 px-3 text-sm duration-200 slide-in-from-top-2">
      <Check className="h-3.5 w-3.5 text-primary" />
      <span className="font-medium text-primary">
        {selectedRows.length} row{selectedRows.length !== 1 ? "s" : ""} selected
      </span>
      <Separator orientation="vertical" className="mx-1 h-4" />

      {/* Custom slot for selection actions */}
      {slots?.selectionActions?.(selectedRows)}

      {/* Default: export selected */}
      <Button
        variant="ghost"
        size="sm"
        className="h-7 gap-1.5"
        onClick={handleExportSelected}
      >
        <Download className="h-3.5 w-3.5" />
        <span className="text-xs">Export selected</span>
      </Button>

      <Button
        variant="ghost"
        size="sm"
        className="ml-auto h-7 gap-1.5"
        onClick={clearSelection}
      >
        <X className="h-3.5 w-3.5" />
        <span className="text-xs">Clear</span>
      </Button>
    </div>
  )
})

// ─── Main Toolbar ─────────────────────────────────────────────────────────────

export const DataGridToolbar = memo(function DataGridToolbar() {
  const { mode, slots } = useDataGridContext()

  return (
    <div>
      <SelectionActionBar />
      <div className="sticky top-0 z-10 flex h-12 items-center gap-2 border-b border-border/60 bg-background/80 px-3 backdrop-blur-md">
        {/* Left slot */}
        {slots?.toolbarLeft}

        <SearchInput />
        <ActiveFiltersBadge />

        {/* Spacer */}
        <div className="flex-1" />

        <ColumnVisibilityToggle />
        <DensityControl />

        {mode === "tree" && <ExpandAllControl />}

        <RefreshButton />
        <ExportButton />
        <AddRowButton />

        {/* Right slot */}
        {slots?.toolbarRight}
      </div>
    </div>
  )
})

import type {
  ColumnMeta,
  GridColumnDef,
} from "@/components/data-grid/types/column-types"
import { cn } from "@/components/data-grid/utils/grid-utils"
import { Badge } from "@/components/ui/badge"
import { Checkbox } from "@/components/ui/checkbox"
import { Check, X } from "lucide-react"

interface BooleanColumnOptions {
  accessorKey: string
  header: string
  editable?: boolean
  trueLabel?: string
  falseLabel?: string
  renderAs?: "badge" | "checkbox" | "icon"
  width?: number
  meta?: Partial<ColumnMeta>
  [key: string]: unknown
}

/**
 * Creates a column definition for boolean data.
 *
 * @param options.accessorKey - The key of the data field to display
 * @param options.header - Column header label
 * @param options.editable - Enable double-click inline editing (default: false)
 * @param options.trueLabel - Label to show when true (default: 'Yes')
 * @param options.falseLabel - Label to show when false (default: 'No')
 * @param options.renderAs - Visual style: 'badge', 'checkbox', or 'icon' (default: 'badge')
 * @param options.width - Base width in pixels (default: 100)
 * @param options.meta - Extra column metadata injected into react-table
 *
 * @example
 * booleanColumn({ accessorKey: 'isActive', header: 'Active', renderAs: 'icon' })
 */
export function booleanColumn(options: BooleanColumnOptions): GridColumnDef {
  const {
    accessorKey,
    header,
    editable,
    trueLabel = "Yes",
    falseLabel = "No",
    renderAs = "badge",
    width,
    meta: extraMeta,
    ...rest
  } = options

  return {
    accessorKey,
    header,
    size: width ?? 100,
    enableSorting: true,
    meta: {
      type: "boolean",
      editable: editable ?? false,
      trueLabel,
      falseLabel,
      renderAs,
      ...extraMeta,
    },
    cell: ({ getValue }) => {
      const value = Boolean(getValue())

      if (renderAs === "checkbox") {
        return (
          <div className="pointer-events-none flex justify-center">
            <Checkbox
              checked={value}
              disabled
              aria-label={value ? trueLabel : falseLabel}
            />
          </div>
        )
      }

      if (renderAs === "icon") {
        return value ? (
          <Check className="h-4 w-4 text-emerald-500" aria-label={trueLabel} />
        ) : (
          <X
            className="h-4 w-4 text-muted-foreground"
            aria-label={falseLabel}
          />
        )
      }

      // default: badge
      return (
        <Badge
          variant="outline"
          className={cn(
            "text-xs font-medium",
            value
              ? "border-emerald-200 bg-emerald-500/10 text-emerald-700 dark:border-emerald-800 dark:text-emerald-400"
              : "text-muted-foreground"
          )}
        >
          {value ? trueLabel : falseLabel}
        </Badge>
      )
    },
    ...rest,
  } as GridColumnDef
}

/* eslint-disable react-refresh/only-export-components */
import type {
  ColumnMeta,
  GridColumnDef,
} from "@/components/data-grid/types/column-types"
import { cn } from "@/components/data-grid/utils/grid-utils"
import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from "@/components/ui/tooltip"
import { Check, Copy } from "lucide-react"
import { useState } from "react"

interface CodeColumnOptions {
  accessorKey: string
  header: string
  editable?: boolean
  language?: string
  copyable?: boolean
  maxLines?: number
  width?: number
  meta?: Partial<ColumnMeta>
  [key: string]: unknown
}

function CodeCopyButton({ value }: { value: string }) {
  const [copied, setCopied] = useState(false)
  const handleCopy = async () => {
    await navigator.clipboard.writeText(value)
    setCopied(true)
    setTimeout(() => setCopied(false), 1500)
  }
  return (
    <button
      onClick={(e) => {
        e.stopPropagation()
        void handleCopy()
      }}
      className="ml-1.5 shrink-0 text-muted-foreground transition-colors hover:text-foreground"
      aria-label="Copy code"
    >
      {copied ? (
        <Check className="h-3 w-3 text-emerald-500" />
      ) : (
        <Copy className="h-3 w-3" />
      )}
    </button>
  )
}

/**
 * Creates a column definition for displaying source code snippets.
 *
 * @param options.accessorKey - The key of the data field to display
 * @param options.header - Column header label
 * @param options.editable - Enable double-click inline editing (default: false)
 * @param options.language - Programming language for syntax highlighting (default: 'text')
 * @param options.copyable - Show a copy button (default: true)
 * @param options.maxLines - Max lines to show before truncating into a tooltip (default: 1)
 * @param options.width - Base width in pixels (default: 220)
 * @param options.meta - Extra column metadata injected into react-table
 *
 * @example
 * codeColumn({ accessorKey: 'payload', header: 'Payload', language: 'json' })
 */
export function codeColumn(options: CodeColumnOptions): GridColumnDef {
  const {
    accessorKey,
    header,
    editable,
    language = "text",
    copyable = true,
    maxLines = 1,
    width,
    meta: extraMeta,
    ...rest
  } = options

  return {
    accessorKey,
    header,
    size: width ?? 220,
    filterFn: "includesString",
    meta: {
      type: "code",
      editable: editable ?? false,
      language,
      copyable,
      maxLines,
      ...extraMeta,
    },
    cell: ({ getValue }) => {
      const raw = getValue<string>() ?? ""
      if (!raw) return null

      const lines = raw.split("\n")
      const isTruncated = lines.length > maxLines
      const display = isTruncated
        ? lines.slice(0, maxLines).join("\n") + "..."
        : raw

      const codeBlock = (
        <div className="flex min-w-0 items-center">
          <code
            className={cn(
              "max-w-full truncate rounded bg-muted/40 px-1.5 py-0.5 font-mono text-[12px]"
            )}
          >
            {display}
          </code>
          {copyable && <CodeCopyButton value={raw} />}
        </div>
      )

      if (isTruncated) {
        return (
          <Tooltip>
            <TooltipTrigger render={<span className="cursor-default" />}>
              {codeBlock}
            </TooltipTrigger>
            <TooltipContent>
              <pre className="max-w-sm font-mono text-[11px] whitespace-pre-wrap">
                {raw}
              </pre>
            </TooltipContent>
          </Tooltip>
        )
      }

      return codeBlock
    },
    ...rest,
  } as GridColumnDef
}

import type {
  ColumnMeta,
  GridColumnDef,
} from "@/components/data-grid/types/column-types"
import { formatDate } from "@/components/data-grid/utils/formatters"
