import type { ColumnMeta, GridColumnDef } from '@/components/data-grid/types/column-types'
import { Copy, Check } from 'lucide-react'
import { useState } from 'react'

interface StringColumnOptions {
  accessorKey: string
  header: string
  editable?: boolean
  copyable?: boolean
  width?: number
  minWidth?: number
  meta?: Partial<ColumnMeta>
  [key: string]: unknown
}

function CopyButton({ value }: { value: string }) {
  const [copied, setCopied] = useState(false)
  const handleCopy = async () => {
    await navigator.clipboard.writeText(value)
    setCopied(true)
    setTimeout(() => setCopied(false), 1500)
  }
  return (
    <button
      onClick={e => { e.stopPropagation(); void handleCopy() }}
      className="ml-1.5 opacity-0 group-hover:opacity-100 transition-opacity text-muted-foreground hover:text-foreground"
      aria-label="Copy value"
    >
      {copied
        ? <Check className="h-3 w-3 text-emerald-500" />
        : <Copy className="h-3 w-3" />
      }
    </button>
  )
}

/**
 * Creates a string column definition.
 *
 * @param options.accessorKey - The key of the data field to display
 * @param options.header - Column header label
 * @param options.editable - Enable double-click inline editing (default: false)
 * @param options.copyable - Show copy button on cell hover (default: false)
 * @param options.width - Base width in pixels (default: 200)
 * @param options.minWidth - Minimum width of the column layout (default: 80)
 * @param options.meta - Extra column metadata injected into react-table
 *
 * @example
 * stringColumn({ accessorKey: 'name', header: 'Name', editable: true, copyable: true })
 */
export function stringColumn(options: StringColumnOptions): GridColumnDef {
  const { accessorKey, header, editable, copyable, width, minWidth, meta: extraMeta, ...rest } = options

  return {
    accessorKey,
    header,
    size: width ?? 200,
    minSize: minWidth ?? 80,
    filterFn: 'includesString',
    meta: {
      type: 'string',
      editable: editable ?? false,
      copyable: copyable ?? false,
      ...extraMeta,
    },
    cell: ({ getValue }) => {
      const value = getValue<string>() ?? ''
      return (
        <div className="flex items-center group truncate">
          <span className="truncate">{value}</span>
          {copyable && value && <CopyButton value={value} />}
        </div>
      )
    },
    ...rest,
  } as GridColumnDef
}

import { useRef, useEffect } from "react"
import type { EditorProps } from "@/components/data-grid/types/editor-types"
import { Switch } from "@/components/ui/switch"
import { cn } from "@/lib/utils"

export function BooleanEditor({ value, onChange, onSave, onCancel }: EditorProps<boolean>) {
  const containerRef = useRef<HTMLDivElement>(null)
  const checked = Boolean(value)

  useEffect(() => {
    containerRef.current?.focus()

    const handler = (e: KeyboardEvent) => {
      if (e.key === "Escape") {
        onCancel()
      }
    }
    document.addEventListener("keydown", handler)
    return () => document.removeEventListener("keydown", handler)
  }, [onCancel])

  // Save on click outside
  useEffect(() => {
    const handler = (e: MouseEvent) => {
      if (containerRef.current && !containerRef.current.contains(e.target as Node)) {
        onChange(checked)
        onSave()
      }
    }
    document.addEventListener("mousedown", handler)
    return () => document.removeEventListener("mousedown", handler)
  }, [checked, onChange, onSave])

  const handleCheckedChange = (next: boolean) => {
    onChange(next)
    onSave()
  }

  return (
    <div
      ref={containerRef}
      tabIndex={-1}
      className={cn(
        "flex items-center justify-center w-full h-full",
        "outline-none",
      )}
    >
      <Switch
        checked={checked}
        onCheckedChange={handleCheckedChange}
      />
    </div>
  )
}

import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { cn } from "@/lib/utils"
import type { EditorProps } from "@/components/data-grid/types/editor-types"
import { X } from "lucide-react"
import React, { useEffect, useRef, useState } from "react"

export function ChipEditor({
  value,
  onChange,
  onSave,
  onCancel,
}: EditorProps<string[]>) {
  const containerRef = useRef<HTMLDivElement>(null)
  const inputRef = useRef<HTMLInputElement>(null)
  const [chips, setChips] = useState<string[]>(
    Array.isArray(value) ? [...(value as string[])] : []
  )
  const [inputVal, setInputVal] = useState("")

  useEffect(() => {
    inputRef.current?.focus()
  }, [])

  // Save on click outside
  useEffect(() => {
    const handler = (e: MouseEvent) => {
      if (
        containerRef.current &&
        !containerRef.current.contains(e.target as Node)
      ) {
        onChange(chips)
        onSave()
      }
    }
    document.addEventListener("mousedown", handler)
    return () => document.removeEventListener("mousedown", handler)
  }, [chips, onChange, onSave])

  const addChip = (text: string) => {
    const trimmed = text.trim()
    if (trimmed && !chips.includes(trimmed)) {
      setChips((prev) => [...prev, trimmed])
    }
    setInputVal("")
  }

  const removeChip = (index: number) => {
    setChips((prev) => prev.filter((_, i) => i !== index))
  }

  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === "Enter") {
      e.preventDefault()
      if (inputVal.trim()) {
        const next = [...chips]
        const trimmed = inputVal.trim()
        if (trimmed && !next.includes(trimmed)) next.push(trimmed)
        setChips(next)
        setInputVal("")
      } else {
        onChange(chips)
        onSave()
      }
    }
    if (e.key === "Escape") {
      e.preventDefault()
      onCancel()
    }
    if (e.key === "Backspace" && inputVal === "" && chips.length > 0) {
      setChips((prev) => prev.slice(0, -1))
    }
  }

  return (
    <div
      ref={containerRef}
      className={cn(
        "flex min-h-full flex-wrap items-center gap-1",
        "px-(--cell-px) py-1",
        "ring-2 ring-primary/60 ring-inset",
        "cursor-text bg-background"
      )}
      onClick={() => inputRef.current?.focus()}
    >
      {chips.map((chip, i) => (
        <Badge
          key={i}
          variant="secondary"
          className="inline-flex items-center gap-0.5 px-1.5 py-0.5 text-xs"
        >
          {chip}
          <Button
            variant="ghost"
            size="icon-xs"
            onClick={(e) => {
              e.stopPropagation()
              removeChip(i)
            }}
            className="ml-0.5 h-auto w-auto p-0 hover:text-destructive"
          >
            <X className="h-2.5 w-2.5" />
          </Button>
        </Badge>
      ))}
      <Input
        ref={inputRef}
        type="text"
        value={inputVal}
        onChange={(e) => setInputVal(e.target.value)}
        onKeyDown={handleKeyDown}
        onBlur={() => {
          if (inputVal.trim()) addChip(inputVal)
        }}
        className="h-auto min-w-16 flex-1 border-0 bg-transparent p-0 text-(length:--font-size) shadow-none outline-none focus-visible:border-transparent focus-visible:ring-0"
        placeholder={chips.length === 0 ? "Add tags…" : ""}
      />
    </div>
  )
}

import { Textarea } from "@/components/ui/textarea"
import { cn } from "@/lib/utils"
import type { EditorProps } from "@/components/data-grid/types/editor-types"
import React, { useEffect, useRef, useState } from "react"

export function CodeEditor({
  value,
  onChange,
  onSave,
  onCancel,
  meta,
}: EditorProps<string>) {
  const ref = useRef<HTMLTextAreaElement>(null)
  const [localValue, setLocalValue] = useState(String(value ?? ""))

  useEffect(() => {
    const el = ref.current
    if (!el) return
    el.focus()
    el.setSelectionRange(el.value.length, el.value.length)
    // Auto-size height
    el.style.height = "auto"
    el.style.height = `${Math.min(el.scrollHeight, 80)}px`
  }, [])

  const autoResize = () => {
    const el = ref.current
    if (!el) return
    el.style.height = "auto"
    el.style.height = `${Math.min(el.scrollHeight, 80)}px`
  }

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if ((e.ctrlKey || e.metaKey) && e.key === "Enter") {
      e.preventDefault()
      onChange(localValue)
      onSave()
    }
    if (e.key === "Escape") {
      e.preventDefault()
      onCancel()
    }
    if (e.key === "Tab") {
      e.preventDefault()
      const el = e.currentTarget
      const start = el.selectionStart
      const end = el.selectionEnd
      const next =
        localValue.substring(0, start) + "  " + localValue.substring(end)
      setLocalValue(next)
      requestAnimationFrame(() => {
        el.selectionStart = start + 2
        el.selectionEnd = start + 2
      })
    }
  }

  const handleBlur = () => {
    if (meta?.saveOnBlur !== false) {
      onChange(localValue)
      onSave()
    }
  }

  return (
    <Textarea
      ref={ref}
      value={localValue}
      onChange={(e) => {
        setLocalValue(e.target.value)
        autoResize()
      }}
      onKeyDown={handleKeyDown}
      onBlur={handleBlur}
      rows={1}
      className={cn(
        "w-full px-(--cell-px) py-(--cell-py)",
        "resize-none overflow-y-auto bg-transparent outline-none",
        "font-mono text-xs",
        "leading-snug",
        "field-sizing-manual min-h-0 rounded-none border-0 shadow-none focus-visible:border-transparent focus-visible:ring-0"
      )}
      style={{ maxHeight: 80 }}
    />
  )
}

import { Button } from "@/components/ui/button"
import { Calendar } from "@/components/ui/calendar"
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover"
import { cn } from "@/lib/utils"
import type { EditorProps } from "@/components/data-grid/types/editor-types"
import { format, isValid, parseISO } from "date-fns"
import { useEffect, useState } from "react"

function parseDate(value: unknown): Date | undefined {
  if (!value) return undefined
  if (value instanceof Date) return isValid(value) ? value : undefined
  if (typeof value === "string") {
    const d = parseISO(value)
    return isValid(d) ? d : undefined
  }
  if (typeof value === "number") {
    const d = new Date(value)
    return isValid(d) ? d : undefined
  }
  return undefined
}

export function DateEditor({
  value,
  onChange,
  onSave,
  onCancel,
}: EditorProps<unknown>) {
  const [open, setOpen] = useState(true)
  const [selected, setSelected] = useState<Date | undefined>(() =>
    parseDate(value)
  )

  // Close + cancel on Escape via keydown on document
  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if (e.key === "Escape") {
        setOpen(false)
        onCancel()
      }
    }
    document.addEventListener("keydown", handler)
    return () => document.removeEventListener("keydown", handler)
  }, [onCancel])

  const handleSelect = (date: Date | undefined) => {
    setSelected(date)
    const isoVal = date ? format(date, "yyyy-MM-dd") : null
    onChange(isoVal as unknown as never)
    setOpen(false)
    onSave()
  }

  const handleClear = () => {
    setSelected(undefined)
    onChange(null as unknown as never)
    setOpen(false)
    onSave()
  }

  const displayLabel = selected
    ? format(selected, "MMM d, yyyy")
    : "Pick a date"

  return (
    <Popover
      open={open}
      onOpenChange={(o) => {
        if (!o) {
          setOpen(false)
          onCancel()
        }
      }}
    >
      <PopoverTrigger
        className={cn(
          "h-full w-full px-(--cell-px) py-(--cell-py)",
          "bg-transparent text-left outline-none",
          "text-(length:--font-size) text-muted-foreground"
        )}
      >
        {displayLabel}
      </PopoverTrigger>
      <PopoverContent className="w-auto p-0" align="start">
        <Calendar
          mode="single"
          selected={selected}
          onSelect={handleSelect}
          initialFocus
        />
        <div className="px-3 pb-3">
          <Button
            variant="ghost"
            size="sm"
            className="w-full text-xs text-muted-foreground"
            onClick={handleClear}
          >
            Clear
          </Button>
        </div>
      </PopoverContent>
    </Popover>
  )
}

import { Input } from "@/components/ui/input"
import { cn } from "@/lib/utils"
import type { EditorProps } from "@/components/data-grid/types/editor-types"
import React, { useEffect, useRef, useState } from "react"

export function NumberEditor({
  value,
  onChange,
  onSave,
  onCancel,
  meta,
}: EditorProps<number>) {
  const ref = useRef<HTMLInputElement>(null)
  const [localValue, setLocalValue] = useState(
    value != null && !isNaN(Number(value)) ? String(value) : ""
  )

  useEffect(() => {
    ref.current?.focus()
    ref.current?.select()
  }, [])

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "Enter") {
      e.preventDefault()
      const num = parseFloat(localValue)
      onChange(isNaN(num) ? (value as number) : num)
      onSave()
    }
    if (e.key === "Escape") {
      e.preventDefault()
      onCancel()
    }
    // Allow: digits, dot, minus, backspace, delete, arrow keys, tab
    const allowed =
      /[0-9.\\-]/.test(e.key) ||
      ["Backspace", "Delete", "ArrowLeft", "ArrowRight", "Tab"].includes(
        e.key
      ) ||
      e.ctrlKey ||
      e.metaKey
    if (!allowed) e.preventDefault()
  }

  const handleBlur = () => {
    if (meta?.saveOnBlur !== false) {
      const num = parseFloat(localValue)
      onChange(isNaN(num) ? (value as number) : num)
      onSave()
    }
  }

  return (
    <Input
      ref={ref}
      type="text"
      inputMode="decimal"
      value={localValue}
      onChange={(e) => setLocalValue(e.target.value)}
      onKeyDown={handleKeyDown}
      onBlur={handleBlur}
      className={cn(
        "h-full w-full px-(--cell-px) py-(--cell-py)",
        "bg-transparent outline-none",
        "text-right font-mono text-(length:--font-size)",
        "rounded-none border-0 shadow-none focus-visible:border-transparent focus-visible:ring-0"
      )}
    />
  )
}

