  PopoverTrigger,
} from "@/components/ui/popover"
import { Slider } from "@/components/ui/slider"
import { ToggleGroup, ToggleGroupItem } from "@/components/ui/toggle-group"
import type { Column } from "@tanstack/react-table"
import { ListFilter } from "lucide-react"
import React from "react"
import type { DateRange } from "react-day-picker"
import { FacetBadge } from "./facet-badge"

interface ColumnFilterPopoverProps {
  column: Column<GridRow, unknown>
}

export function ColumnFilterPopover({ column }: ColumnFilterPopoverProps) {
  const meta = column.columnDef.meta as ColumnMeta | undefined
  const columnType = meta?.type ?? "string"
  const isFiltered = column.getIsFiltered()

  return (
    <Popover>
      <PopoverTrigger
        className="inline-flex items-center justify-center focus:outline-none"
        aria-label="Filter column"
      >
        {isFiltered ? (
          <FacetBadge count={1} />
        ) : (
          <ListFilter className="h-3.5 w-3.5 text-muted-foreground/40 opacity-0 transition-opacity group-hover/header:opacity-100" />
        )}
      </PopoverTrigger>
      <PopoverContent
        className={columnType === "number" ? "w-64" : "w-56"}
        side="bottom"
        align="start"
      >
        <div className="flex flex-col gap-2">
          <FilterContent column={column} columnType={columnType} meta={meta} />
          <Button
            variant="ghost"
            size="sm"
            className="h-7 w-full justify-start text-xs text-muted-foreground hover:text-foreground"
            onClick={() => column.setFilterValue(undefined)}
          >
            Clear filter
          </Button>
        </div>
      </PopoverContent>
    </Popover>
  )
}

// ─────────────────────────────────────────────────────────────────────────────
// Dispatch to type-specific filter UI
// ─────────────────────────────────────────────────────────────────────────────

function FilterContent({
  column,
  columnType,
  meta,
}: {
  column: Column<GridRow, unknown>
  columnType: ColumnType
  meta: ColumnMeta | undefined
}) {
  switch (columnType) {
    case "string":
    case "code":
      return <StringFilter column={column} />
    case "number":
      return <NumberFilter column={column} />
    case "date":
      return <DateFilter column={column} />
    case "multi-value":
      return <MultiValueFilter column={column} />
    case "select":
      return <SelectTypeFilter column={column} options={meta?.options} />
    case "boolean":
      return <BooleanFilter column={column} />
    default:
      return <StringFilter column={column} />
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// String / Code filter
// ─────────────────────────────────────────────────────────────────────────────

type StringFilterValue = { value: string; operator: "contains" | "startsWith" }

function StringFilter({ column }: { column: Column<GridRow, unknown> }) {
  const current = (column.getFilterValue() as
    | StringFilterValue
    | undefined) ?? {
    value: "",
    operator: "contains" as const,
  }
  const [localValue, setLocalValue] = React.useState(current.value)
  const [operator, setOperator] = React.useState<"contains" | "startsWith">(
    current.operator
  )

  const apply = (v: string, op: "contains" | "startsWith") => {
    column.setFilterValue(v ? { value: v, operator: op } : undefined)
  }

  return (
    <div className="flex flex-col gap-1.5">
      <div className="flex gap-1">
        {(["contains", "startsWith"] as const).map((op) => (
          <button
            key={op}
            onClick={() => {
              setOperator(op)
              apply(localValue, op)
            }}
            className={`rounded border px-1.5 py-0.5 text-[10px] transition-colors ${
              operator === op
                ? "border-primary bg-primary/10 text-primary"
                : "border-border text-muted-foreground hover:border-foreground/30"
            }`}
          >
            {op === "contains" ? "contains" : "starts with"}
          </button>
        ))}
      </div>
      <Input
        className="h-7 text-xs"
        placeholder="Filter..."
        value={localValue}
        onChange={(e) => {
          setLocalValue(e.target.value)
          apply(e.target.value, operator)
        }}
      />
    </div>
  )
}

// ─────────────────────────────────────────────────────────────────────────────
// Number filter — dual-thumb range slider
// ─────────────────────────────────────────────────────────────────────────────

function NumberFilter({ column }: { column: Column<GridRow, unknown> }) {
  const facetMinMax = column.getFacetedMinMaxValues()
  const facetMin = facetMinMax?.[0] ?? 0
  const facetMax = facetMinMax?.[1] ?? 100

  const currentFilter = column.getFilterValue() as [number, number] | undefined
  const [range, setRange] = React.useState<[number, number]>([
    currentFilter?.[0] ?? facetMin,
    currentFilter?.[1] ?? facetMax,
  ])

  const handleSliderChange = (values: number[]) => {
    const next: [number, number] = [values[0], values[1]]
    setRange(next)
    column.setFilterValue(next)
  }

  const handleMinInput = (e: React.ChangeEvent<HTMLInputElement>) => {
    const v = parseFloat(e.target.value)
    if (isNaN(v)) return
    const next: [number, number] = [v, range[1]]
    setRange(next)
    column.setFilterValue(next)
  }

  const handleMaxInput = (e: React.ChangeEvent<HTMLInputElement>) => {
    const v = parseFloat(e.target.value)
    if (isNaN(v)) return
    const next: [number, number] = [range[0], v]
    setRange(next)
    column.setFilterValue(next)
  }

  return (
    <div className="flex flex-col gap-2">
      <div className="flex gap-1.5">
        <Input
          className="h-6 w-full text-xs"
          type="number"
          value={range[0]}
          onChange={handleMinInput}
          placeholder="Min"
        />
        <span className="self-center text-xs text-muted-foreground">–</span>
        <Input
          className="h-6 w-full text-xs"
          type="number"
          value={range[1]}
          onChange={handleMaxInput}
          placeholder="Max"
        />
      </div>
      <Slider
        min={facetMin}
        max={facetMax}
        value={range}
        onValueChange={(value: number | readonly number[]) => {
          const arr = Array.isArray(value) ? [...value] : [value as number]
          handleSliderChange(arr)
        }}
        className="my-1"
      />
      <div className="flex justify-between text-[10px] text-muted-foreground">
        <span>{facetMin}</span>
        <span>{facetMax}</span>
      </div>
    </div>
  )
}

// ─────────────────────────────────────────────────────────────────────────────
// Date range filter — dual calendar
// ─────────────────────────────────────────────────────────────────────────────

type DateFilterValue = { from?: string; to?: string }

function DateFilter({ column }: { column: Column<GridRow, unknown> }) {
  const current = column.getFilterValue() as DateFilterValue | undefined
  const [range, setRange] = React.useState<DateRange>({
    from: current?.from ? new Date(current.from) : undefined,
    to: current?.to ? new Date(current.to) : undefined,
  })

  const handleSelect = (selected: DateRange | undefined) => {
    setRange(selected ?? { from: undefined, to: undefined })
    column.setFilterValue(
      selected?.from || selected?.to
        ? {
            from: selected?.from?.toISOString(),
            to: selected?.to?.toISOString(),
          }
        : undefined
    )
  }

  return (
    <Calendar
      mode="range"
      selected={range}
      onSelect={handleSelect}
      className="p-0 text-xs [--cell-size:--spacing(6)]"
      numberOfMonths={1}
    />
  )
}

// ─────────────────────────────────────────────────────────────────────────────
// Multi-value filter — checkbox list with facet counts
// ─────────────────────────────────────────────────────────────────────────────

function MultiValueFilter({ column }: { column: Column<GridRow, unknown> }) {
  const facetMap = column.getFacetedUniqueValues()
  const selected = (column.getFilterValue() as string[] | undefined) ?? []

  // Flatten: multi-value cells may be arrays; accumulate per-tag counts
  const tagCounts = React.useMemo(() => {
    const acc = new Map<string, number>()
    facetMap.forEach((count, rawValue) => {
      if (Array.isArray(rawValue)) {
        rawValue.forEach((tag) => {
          acc.set(String(tag), (acc.get(String(tag)) ?? 0) + count)
        })
      } else if (rawValue !== null && rawValue !== undefined) {
        const k = String(rawValue)
        acc.set(k, (acc.get(k) ?? 0) + count)
      }
    })
    return acc
  }, [facetMap])

  const sortedTags = React.useMemo(
    () => [...tagCounts.entries()].sort((a, b) => b[1] - a[1]).slice(0, 20),
    [tagCounts]
  )

  const toggle = (tag: string) => {
    const next = selected.includes(tag)
      ? selected.filter((v) => v !== tag)
      : [...selected, tag]
    column.setFilterValue(next.length ? next : undefined)
  }

  return (
    <div className="flex max-h-48 flex-col gap-1 overflow-y-auto">
      {sortedTags.map(([tag, count]) => (
        <label
          key={tag}
          className="flex cursor-pointer items-center gap-2 rounded px-1 py-0.5 text-xs hover:bg-muted/40"
        >
          <Checkbox
            checked={selected.includes(tag)}
            onCheckedChange={() => toggle(tag)}
            className="h-3 w-3"
          />
          <span className="flex-1 truncate">{tag}</span>
          <span className="ml-auto shrink-0 text-[10px] text-muted-foreground">
            ({count})
          </span>
        </label>
      ))}
    </div>
  )
}

// ─────────────────────────────────────────────────────────────────────────────
// Select filter — checkbox list with facet counts
// ─────────────────────────────────────────────────────────────────────────────

function SelectTypeFilter({
  column,
  options,
}: {
  column: Column<GridRow, unknown>
  options?: SelectOption[]
}) {
  const facetMap = column.getFacetedUniqueValues()
  const selected = (column.getFilterValue() as string[] | undefined) ?? []

  // eslint-disable-next-line react-hooks/preserve-manual-memoization
  const items = React.useMemo(() => {
    const fromFacet = [...facetMap.entries()]
      .filter(([v]) => v !== null && v !== undefined)
      .map(([v, count]) => ({ value: String(v), count }))
      .sort((a, b) => b.count - a.count)

    if (options) {
      return options.map((opt) => ({
        value: opt.value,
        label: opt.label,
        count: facetMap.get(opt.value) ?? 0,
      }))
    }
    return fromFacet.map((f) => ({
      value: f.value,
      label: f.value,
      count: f.count,
    }))
  }, [facetMap, options])

  const toggle = (value: string) => {
    const next = selected.includes(value)
      ? selected.filter((v) => v !== value)
      : [...selected, value]
    column.setFilterValue(next.length ? next : undefined)
  }

  return (
    <div className="flex max-h-48 flex-col gap-1 overflow-y-auto">
      {items.map((item) => (
        <label
          key={item.value}
          className="flex cursor-pointer items-center gap-2 rounded px-1 py-0.5 text-xs hover:bg-muted/40"
        >
          <Checkbox
            checked={selected.includes(item.value)}
            onCheckedChange={() => toggle(item.value)}
            className="h-3 w-3"
          />
          <span className="flex-1 truncate">{item.label}</span>
          <span className="ml-auto shrink-0 text-[10px] text-muted-foreground">
            ({item.count})
          </span>
        </label>
      ))}
    </div>
  )
}

// ─────────────────────────────────────────────────────────────────────────────
// Boolean filter — All / True / False toggle group
// ─────────────────────────────────────────────────────────────────────────────

type BoolVal = "all" | "true" | "false"

function BooleanFilter({ column }: { column: Column<GridRow, unknown> }) {
  const raw = column.getFilterValue() as string | undefined
  const current: BoolVal =
    raw === "true" ? "true" : raw === "false" ? "false" : "all"

  const handleSelect = (val: BoolVal) => {
    column.setFilterValue(val === "all" ? undefined : val)
  }

  return (
    <ToggleGroup variant="outline" size="sm" className="w-full">
      {(["all", "true", "false"] as BoolVal[]).map((val) => (
        <ToggleGroupItem
          key={val}
          pressed={current === val}
          onPressedChange={(p: boolean) => {
            if (p) handleSelect(val)
          }}
          className="flex-1 text-xs"
        >
          {val === "all" ? "All" : val === "true" ? "True" : "False"}
        </ToggleGroupItem>
      ))}
    </ToggleGroup>
  )
}

import { ListFilter } from "lucide-react"

interface FacetBadgeProps {
  count?: number
}

export function FacetBadge({ count }: FacetBadgeProps) {
  return (
    <span className="inline-flex items-center gap-0.5">
      <ListFilter className="h-3.5 w-3.5 text-primary" />
      {count !== undefined && count > 0 && (
        <span className="text-[10px] bg-primary text-primary-foreground rounded-full px-1 leading-tight font-medium">
          {count}
        </span>
      )}
    </span>
  )
}

import type { FilterFn } from "@tanstack/react-table"
import type { GridRow } from "@/components/data-grid/types/grid-types"
import type { ColumnType } from "@/components/data-grid/types/column-types"

// Module augmentation for custom filter function names
declare module "@tanstack/react-table" {
  interface FilterFns {
    fuzzy: FilterFn<unknown>
    stringFilter: FilterFn<unknown>
    dateRangeFilter: FilterFn<unknown>
    multiValueFilter: FilterFn<unknown>
    selectFilter: FilterFn<unknown>
    booleanFilter: FilterFn<unknown>
  }
}

// String filter — supports { value, operator } shape
export const stringFilter: FilterFn<GridRow> = (
  row,
  columnId,
  filterValue: unknown,
): boolean => {
  if (!filterValue || typeof filterValue !== "object") return true
  const { value, operator } = filterValue as {
    value: string
    operator: "contains" | "startsWith"
  }
  if (!value) return true
  const cellValue = String(row.getValue(columnId) ?? "").toLowerCase()
  const q = value.toLowerCase()
  return operator === "startsWith" ? cellValue.startsWith(q) : cellValue.includes(q)
}
stringFilter.autoRemove = (val: unknown) => {
  if (!val || typeof val !== "object") return true
  return !(val as { value?: string }).value
}

// Date range filter — { from?: string, to?: string } (ISO strings)
export const dateRangeFilter: FilterFn<GridRow> = (
  row,
  columnId,
  filterValue: unknown,
): boolean => {
  if (!filterValue || typeof filterValue !== "object") return true
  const { from, to } = filterValue as { from?: string; to?: string }
  if (!from && !to) return true
  const cellRaw = row.getValue<string | Date | null>(columnId)
  if (cellRaw === null || cellRaw === undefined) return false
  const cellDate = new Date(cellRaw)
  if (isNaN(cellDate.getTime())) return false
  if (from) {
    const fromDate = new Date(from)
    fromDate.setHours(0, 0, 0, 0)
    if (cellDate < fromDate) return false
  }
  if (to) {
    const toDate = new Date(to)
    toDate.setHours(23, 59, 59, 999)
    if (cellDate > toDate) return false
  }
  return true
}
dateRangeFilter.autoRemove = (val: unknown) => {
  if (!val || typeof val !== "object") return true
  const { from, to } = val as { from?: string; to?: string }
  return !from && !to
}

// Multi-value filter — filters array cells for any match
export const multiValueFilter: FilterFn<GridRow> = (
  row,
  columnId,
  filterValue: unknown,
): boolean => {
  if (!Array.isArray(filterValue) || filterValue.length === 0) return true
  const cellRaw = row.getValue<string[] | string | null>(columnId)
  if (cellRaw === null || cellRaw === undefined) return false
  const cellArr = Array.isArray(cellRaw)
    ? cellRaw.map(String)
    : [String(cellRaw)]
  return (filterValue as string[]).some((v) => cellArr.includes(v))
}
multiValueFilter.autoRemove = (val: unknown) =>
  !Array.isArray(val) || val.length === 0

// Select filter — checks if single cell value is in selected set
export const selectFilter: FilterFn<GridRow> = (
  row,
  columnId,
  filterValue: unknown,
): boolean => {
  if (!Array.isArray(filterValue) || filterValue.length === 0) return true
  const cellValue = String(row.getValue(columnId) ?? "")
  return (filterValue as string[]).includes(cellValue)
}
selectFilter.autoRemove = (val: unknown) =>
  !Array.isArray(val) || val.length === 0

// Boolean filter — 'true' | 'false' (undefined = all)
export const booleanFilter: FilterFn<GridRow> = (
  row,
  columnId,
  filterValue: unknown,
): boolean => {
  if (!filterValue || filterValue === "all") return true
  const cellValue = Boolean(row.getValue(columnId))
  return filterValue === "true" ? cellValue : !cellValue
}
booleanFilter.autoRemove = (val: unknown) => !val || val === "all"

// Maps column type to custom filter function name
export function filterFnForType(type: ColumnType | undefined): string | undefined {
  switch (type) {
    case "string":
    case "code":
      return "stringFilter"
    case "number":
      return "inNumberRange"
    case "date":
      return "dateRangeFilter"
    case "multi-value":
      return "multiValueFilter"
    case "select":
      return "selectFilter"
    case "boolean":
      return "booleanFilter"
    default:
      return undefined
  }
}

import { useDataGridContext } from "@/components/data-grid/data-grid-context"
import type {
  ColumnMeta,
  ColumnType,
} from "@/components/data-grid/types/column-types"
import type { GridRow } from "@/components/data-grid/types/grid-types"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { TableCell, TableRow } from "@/components/ui/table"
import type { Column, Header } from "@tanstack/react-table"
import React from "react"

export function FilterRow() {
  const { table } = useDataGridContext()
  const headerGroups = table.getHeaderGroups()
  const leafHeaderGroup = headerGroups[headerGroups.length - 1]

  return (
    <TableRow className="border-b-2 border-border bg-background">
      {leafHeaderGroup.headers.map((header) => (
        <FilterRowCell key={header.id} header={header} />
      ))}
    </TableRow>
  )
}

function FilterRowCell({ header }: { header: Header<GridRow, unknown> }) {
  const { column } = header
  const meta = column.columnDef.meta as ColumnMeta | undefined
  const columnType = meta?.type ?? "string"

  return (
    <TableCell
      style={{ width: `${header.getSize()}px` }}
      className="px-(--cell-px) py-1"
    >
      {!header.isPlaceholder && (
        <FilterRowControl column={column} columnType={columnType} meta={meta} />
      )}
    </TableCell>
  )
}

function FilterRowControl({
  column,
  columnType,
  meta,
}: {
  column: Column<GridRow, unknown>
  columnType: ColumnType
  meta: ColumnMeta | undefined
}) {
  const inputClass =
    "h-7 text-xs border-0 bg-transparent focus:ring-1 focus:ring-primary/40 px-1.5"

  switch (columnType) {
    case "string":
    case "code":
      return <StringRowFilter column={column} className={inputClass} />
    case "number":
      return <NumberRowFilter column={column} className={inputClass} />
    case "date":
      return <DateRowFilter column={column} className={inputClass} />
    case "select":
      return (
        <SelectRowFilter
          column={column}
          className={inputClass}
          options={meta?.options}
        />
      )
    case "multi-value":
      return <StringRowFilter column={column} className={inputClass} />
    case "boolean":
      return <BooleanRowFilter column={column} />
    default:
      return <StringRowFilter column={column} className={inputClass} />
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// Per-type row controls
// ─────────────────────────────────────────────────────────────────────────────

function StringRowFilter({
  column,
  className,
}: {
  column: Column<GridRow, unknown>
  className: string
}) {
  const current = column.getFilterValue() as
    | { value: string; operator: "contains" | "startsWith" }
    | undefined
  const [value, setValue] = React.useState(current?.value ?? "")

  React.useEffect(() => {
    const v = (
      column.getFilterValue() as { value: string; operator: string } | undefined
    )?.value
    if (v !== value) setValue(v ?? "")
    // only sync when filter is cleared externally
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [column.getFilterValue()])

  return (
    <Input
      className={className}
      placeholder="Filter…"
      value={value}
      onChange={(e) => {
        setValue(e.target.value)
        column.setFilterValue(
          e.target.value
            ? { value: e.target.value, operator: "contains" }
            : undefined
        )
      }}
    />
  )
}

function NumberRowFilter({
  column,
  className,
}: {
  column: Column<GridRow, unknown>
  className: string
}) {
  const current = column.getFilterValue() as [number, number] | undefined
  const [min, setMin] = React.useState(
    current?.[0] !== undefined ? String(current[0]) : ""
  )
  const [max, setMax] = React.useState(
    current?.[1] !== undefined ? String(current[1]) : ""
  )

  const commit = (minVal: string, maxVal: string) => {
    const minN = minVal !== "" ? parseFloat(minVal) : undefined
    const maxN = maxVal !== "" ? parseFloat(maxVal) : undefined
    if (minN === undefined && maxN === undefined) {
      column.setFilterValue(undefined)
    } else {
      const facetMinMax = column.getFacetedMinMaxValues()
      column.setFilterValue([
        minN ?? facetMinMax?.[0] ?? 0,
        maxN ?? facetMinMax?.[1] ?? Infinity,
      ])
    }
  }

  return (
    <div className="flex gap-1">
      <Input
        className={className + " w-1/2"}
        type="number"
        placeholder="Min"
        value={min}
        onChange={(e) => {
          setMin(e.target.value)
          commit(e.target.value, max)
        }}
      />
      <Input
        className={className + " w-1/2"}
        type="number"
        placeholder="Max"
        value={max}
        onChange={(e) => {
          setMax(e.target.value)
          commit(min, e.target.value)
        }}
      />
    </div>
  )
}

function DateRowFilter({
  column,
  className,
}: {
  column: Column<GridRow, unknown>
  className: string
}) {
  const current = column.getFilterValue() as
    | { from?: string; to?: string }
    | undefined
  const [from, setFrom] = React.useState(
    current?.from ? new Date(current.from).toISOString().slice(0, 10) : ""
  )
  const [to, setTo] = React.useState(
    current?.to ? new Date(current.to).toISOString().slice(0, 10) : ""
  )

  const commit = (f: string, t: string) => {
    column.setFilterValue(
      f || t
        ? {
            from: f ? new Date(f).toISOString() : undefined,
            to: t ? new Date(t).toISOString() : undefined,
          }
        : undefined
    )
  }

  return (
    <div className="flex gap-1">
      <Input
        className={className + " w-1/2"}
        type="date"
        value={from}
        onChange={(e) => {
          setFrom(e.target.value)
          commit(e.target.value, to)
        }}
      />
      <Input
        className={className + " w-1/2"}
        type="date"
        value={to}
        onChange={(e) => {
          setTo(e.target.value)
          commit(from, e.target.value)
        }}
      />
    </div>
  )
}

import type { SelectOption } from "@/components/data-grid/types/column-types"

function SelectRowFilter({
  column,
  className,
  options,
}: {
  column: Column<GridRow, unknown>
  className: string
  options?: SelectOption[]
}) {
  const facetMap = column.getFacetedUniqueValues()
  const items = options
    ? options.map((o) => ({ value: o.value, label: o.label }))
    : [...facetMap.keys()]
        .filter((v) => v !== null && v !== undefined)
        .map((v) => ({ value: String(v), label: String(v) }))

  const current = (column.getFilterValue() as string[] | undefined) ?? []

  return (
    <Select
      value={current[0] ?? ""}
      onValueChange={(val) => {
        column.setFilterValue(val && val !== "__all__" ? [val] : undefined)
      }}
    >
      <SelectTrigger
        className={
          className + " w-full rounded-none border border-border bg-background"
        }
      >
        <SelectValue placeholder="All" />
      </SelectTrigger>
      <SelectContent>
