export type PaginatedQueryFn<TData> = (params: {
  pageIndex: number
  pageSize: number
  sort: SortState[]
  filters: FilterState[]
}) => Promise<{ rows: TData[]; total: number }>

export type InfiniteQueryFn<TData> = (params: {
  pageParam: number
  sort: SortState[]
  filters: FilterState[]
}) => Promise<InfinitePageResult<TData>>

/**
 * Configuration for the useDataGrid hook.
 * Shared mostly with DataGridProps, but tailored for internal hook usage.
 */
export interface DataGridConfig<TData extends GridRow> {
  /** Array of rows for client-side modes (flat and tree) */
  data?: TData[]
  /** Array of column configurations */
  columns: GridColumnDef<TData>[]
  /** Operation mode of the grid. 'flat', 'tree', 'paginated', or 'infinite' */
  mode?: GridMode
  /** Visual density spacing */
  density?: GridDensity
  /** Settings for interactive grid features (sorting, filtering, editing, etc.) */
  features?: GridFeaturesConfig
  /** Render overrides for specific wrapper sections of the grid */
  slots?: GridSlots
  /** Function to extract nested children arrays for Tree mode */
  getSubRows?: (row: TData) => TData[] | undefined
  /** Async callback fired when expanding a node in Tree mode */
  onExpand?: (row: GridRow) => Promise<GridRow[]> | void
  /** Indicates if remote data is currently refetching */
  isRefetching?: boolean
  /** Indicates if an infinite scroll query is fetching the next page */
  isFetchingNextPage?: boolean
  /** Indicates if data is currently loading */
  isLoading?: boolean
  /** Action handler for the toolbar refresh button */
  onRefresh?: () => void
  /** Required QueryKey for query-driven modes (paginated, infinite) */
  queryKey?: QueryKey
  /** Data fetching query function for server modes */
  queryFn?: PaginatedQueryFn<TData> | InfiniteQueryFn<TData>
  /**
   * Initial column visibility state. Columns listed as false are hidden on mount.
   * Produced by the table engine's column-builder from ColumnConfig.visible settings.
   * Example: { internalCode: false, notes: false }
   */
  initialColumnVisibility?: Record<string, boolean>
}

/**
 * Headless hook that manages state and orchestration for TanStack Table wrapped with internal features.
 * Integrates directly with sorting, filtering, row selection, pinning, grouping, editing, and virtualization hooks.
 * config:
 *  - data: Array of rows for client-side modes (flat and tree)
 *  - columns: Array of column configurations
 *  - mode: Operation mode of the grid. 'flat', 'tree', 'paginated', or 'infinite'
 *  - density: Visual density spacing
 *  - features: Settings for interactive grid features (sorting, filtering, editing, etc.)
 *  - slots: Render overrides for specific wrapper sections of the grid
 *  - getSubRows: Function to extract nested children arrays for Tree mode
 *  - onExpand: Async callback fired when expanding a node in Tree mode
 *  - isRefetching: Indicates if remote data is currently refetching
 *  - isFetchingNextPage: Indicates if an infinite scroll query is fetching the next page
 *  - onRefresh: Action handler for the toolbar refresh button
 *  - queryKey: Required QueryKey for query-driven modes (paginated, infinite)
 *  - queryFn: Data fetching query function for server modes
 * @param config DataGrid parameters and configuration flags
 * @returns An aggregated state context object ready to be provided to grid UI components via DataGridProvider
 */
export function useDataGrid<TData extends GridRow>(
  config: DataGridConfig<TData>
): DataGridContextValue {
  const {
    columns,
    density: initialDensity = "normal",
    features,
    mode,
    slots,
    isRefetching: externalIsRefetching = false,
    isFetchingNextPage: externalIsFetchingNextPage = false,
    isLoading: externalIsLoading = false,
    onRefresh,
    initialColumnVisibility,
  } = config

  const [density, setDensity] = React.useState<GridDensity>(initialDensity)
  const [columnVisibility, setColumnVisibility] = React.useState<
    Record<string, boolean>
  >(initialColumnVisibility ?? {})
  const tableContainerRef = React.useRef<HTMLDivElement>(null)

  // Pagination state (for paginated mode)
  const [pagination, setPagination] = React.useState({
    pageIndex: 0,
    pageSize: 50,
  })

  const isServerMode = mode === "paginated" || mode === "infinite"

  // Feature hooks
  const sortingHook = useSorting({
    ...features?.sorting,
    mode: isServerMode ? "server" : (features?.sorting?.mode ?? "client"),
  })
  const filteringHook = useFiltering({
    ...features?.filtering,
    mode: isServerMode ? "server" : (features?.filtering?.mode ?? "client"),
  })
  const resizeHook = useColumnResize()
  const selectionHook = useSelection(features?.selection)
  const columnPinningHook = useColumnPinning(features?.columnPinning)
  const rowPinningHook = useRowPinning(features?.rowPinning)
  const groupingHook = useGrouping(features?.grouping)
  const orderingHook = useColumnOrdering()

  // Convert TanStack Table sorting/filtering state to SortState[]/FilterState[]
  const sortState = React.useMemo<SortState[]>(
    () =>
      sortingHook.sortingState.map((s) => ({
        columnId: s.id,
        direction: s.desc ? ("desc" as const) : ("asc" as const),
      })),
    [sortingHook.sortingState]
  )
  const filterState = React.useMemo<FilterState[]>(
    () =>
      filteringHook.columnFilters.map((f) => ({
        columnId: f.id,
        value: f.value,
      })),
    [filteringHook.columnFilters]
  )

  // Paginated query (always called, enabled only when mode === 'paginated')
  const paginatedQuery = useQuery({
    queryKey: [
      ...(config.queryKey ?? []),
      {
        page: pagination.pageIndex,
        pageSize: pagination.pageSize,
        sort: sortState,
        filters: filterState,
      },
    ],
    queryFn: () =>
      (config.queryFn as PaginatedQueryFn<TData>)({
        pageIndex: pagination.pageIndex,
        pageSize: pagination.pageSize,
        sort: sortState,
        filters: filterState,
      }),
    enabled: mode === "paginated" && !!config.queryKey,
    placeholderData: keepPreviousData,
  })

  // Infinite query (always called, enabled only when mode === 'infinite')
  const infiniteQuery = useInfiniteData<TData>({
    queryKey: config.queryKey ?? [],
    queryFn: config.queryFn as InfiniteQueryFn<TData>,
    sortState,
    filterState,
    enabled: mode === "infinite" && !!config.queryKey,
  })

  // Editing
  const editingHook = useEditing(features?.editing)

  // Loading state
  const loadingState = useLoadingState({
    enabled: features?.loading?.enabled,
    isRefetching: externalIsRefetching,
    isFetchingNextPage: externalIsFetchingNextPage,
    isMutating: editingHook.mutatingRowIds.size > 0,
  })

  // Determine effective data source based on mode
  const effectiveData = React.useMemo<TData[]>(() => {
    if (mode === "paginated")
      return (paginatedQuery.data?.rows ?? []) as TData[]
    if (mode === "infinite") return infiniteQuery.rows as TData[]
    return (config.data ?? []) as TData[]
  }, [mode, paginatedQuery.data, infiniteQuery.rows, config.data])

  // Internal data state — allows lazy tree expand to merge children
  const [internalData, setInternalData] = React.useState<TData[]>(effectiveData)
  React.useEffect(() => {
    setInternalData(effectiveData)
  }, [effectiveData])

  // Reset page to 0 on sort/filter change (paginated mode)
  React.useEffect(() => {
    if (mode === "paginated") {
      setPagination((prev) => ({ ...prev, pageIndex: 0 }))
    }
  }, [sortingHook.sortingState, filteringHook.columnFilters, mode])

  // Lazy tree expand
  const { loadingRowIds, handleExpand } = useLazyExpand({
    onExpand: config.onExpand,
    setData: setInternalData as React.Dispatch<React.SetStateAction<GridRow[]>>,
  })

  // Post-process columns: add filterFn + aggregationFn per column type
  const processedColumns = React.useMemo(
    () =>
      columns.map((col) => {
        const type = col.meta?.type as ColumnType | undefined
        const fn = filterFnForType(type)
        return {
          ...col,
          ...(fn ? { filterFn: fn as FilterFnOption<TData> } : {}),
          ...(type === "number" ? { aggregationFn: "sum" as const } : {}),
        }
      }),
    [columns]
  )

  // Inject special columns
  const finalColumns = React.useMemo(() => {
    let cols: GridColumnDef<TData>[] = processedColumns
    if (features?.selection?.enabled) {
      cols = [selectionColumnDef as GridColumnDef<TData>, ...cols]
    }
    if (mode === "tree") {
      cols = [expandColumnDef as GridColumnDef<TData>, ...cols]
    }
    return cols
  }, [features?.selection?.enabled, mode, processedColumns])

  // Destructure all table options from hooks
  const {
    manualSorting,
    onSortingChange,
    enableMultiSort,
    sortDescFirst,
    manualFiltering,
    filterFns,
    globalFilterFn,
    onColumnFiltersChange,
    onGlobalFilterChange,
    columnResizeMode,
    enableColumnResizing,
    columnResizeDirection,
    enableRowSelection,
    enableMultiRowSelection,
    onRowSelectionChange,
    enableColumnPinning,
    onColumnPinningChange,
    enableRowPinning,
    keepPinnedRows,
    onRowPinningChange,
    enableGrouping,
    groupedColumnMode,
    onGroupingChange,
    onExpandedChange,
    autoResetExpanded,
    onColumnOrderChange,
  } = {
    ...sortingHook.tableOptions,
    ...filteringHook.tableOptions,
    ...resizeHook.tableOptions,
    ...selectionHook.tableOptions,
    ...columnPinningHook.tableOptions,
    ...rowPinningHook.tableOptions,
    ...groupingHook.tableOptions,
    ...orderingHook.tableOptions,
  }

  const table = useReactTable<TData>({
    data: internalData,
    columns: finalColumns,
    getCoreRowModel: getCoreRowModel(),
    getSortedRowModel: getSortedRowModel(),
    getFilteredRowModel: getFilteredRowModel(),
    getFacetedRowModel: getFacetedRowModel(),
    getFacetedUniqueValues: getFacetedUniqueValues(),
    getFacetedMinMaxValues: getFacetedMinMaxValues(),
    getGroupedRowModel: getGroupedRowModel(),
    getExpandedRowModel: getExpandedRowModel(),
    // Tree mode: teach TanStack Table how to traverse child rows
    ...(mode === "tree"
      ? {
          getSubRows: (row: TData) =>
            config.getSubRows
              ? config.getSubRows(row)
              : (row.children as TData[] | undefined),
          enableExpanding: true,
          autoResetExpanded: false,
        }
      : {}),
    // Paginated mode: manual pagination with server-driven row count
    ...(mode === "paginated"
      ? {
          manualPagination: true,
          rowCount: paginatedQuery.data?.total ?? -1,
          onPaginationChange: setPagination,
        }
      : {}),
    state: {
      sorting: sortingHook.sortingState,
      columnFilters: filteringHook.columnFilters,
      globalFilter: filteringHook.globalFilter,
      columnVisibility,
      rowSelection: selectionHook.rowSelection,
      columnPinning: columnPinningHook.columnPinning,
      rowPinning: rowPinningHook.rowPinning,
      grouping: groupingHook.grouping,
      expanded: groupingHook.expanded,
      columnOrder: orderingHook.columnOrder,
      ...(mode === "paginated" ? { pagination } : {}),
    },
    onColumnVisibilityChange: setColumnVisibility,
    // Sorting
    manualSorting,
    onSortingChange,
    enableMultiSort,
    sortDescFirst,
    // Filtering
    manualFiltering,
    filterFns,
    globalFilterFn,
    onColumnFiltersChange,
    onGlobalFilterChange,
    // Resize
    columnResizeMode,
    enableColumnResizing,
    columnResizeDirection,
    // Selection
    enableRowSelection,
    enableMultiRowSelection,
    onRowSelectionChange,
    // Column pinning
    enableColumnPinning,
    onColumnPinningChange,
    // Row pinning
    enableRowPinning,
    keepPinnedRows,
    onRowPinningChange,
    // Grouping
    enableGrouping,
    groupedColumnMode,
    onGroupingChange,
    onExpandedChange,
    autoResetExpanded,
    // Column ordering
    onColumnOrderChange,
  })

  // Row virtualization — count center rows for flat, all visible rows for tree
  const rowsForVirtualizer =
    mode === "tree" ? table.getRowModel().rows : table.getCenterRows()
  const rowVirtualizer = useRowVirtualizer({
    enabled: features?.virtualization?.enabled ?? false,
    rowCount: rowsForVirtualizer.length,
    density,
    rowHeight: features?.virtualization?.rowHeight,
    containerRef: tableContainerRef,
    overscan: features?.virtualization?.overscan,
  })

  // Column virtualization — only center (non-pinned) columns
  const centerColumns = table.getCenterLeafColumns()
  const columnVirtualizer = useColVirtualizer({
    enabled: features?.virtualization?.enabled ?? false,
    columns: centerColumns,
    containerRef: tableContainerRef,
  })

  // Determine effective isLoading based on mode
  const isLoading =
    externalIsLoading ||
    (mode === "paginated"
      ? paginatedQuery.isLoading
      : mode === "infinite"
        ? infiniteQuery.isLoading
        : loadingState.isInitialLoading)

  return React.useMemo<DataGridContextValue>(
    () => ({
      table: table as unknown as Table<GridRow>,
      isLoading,
      isRefetching: loadingState.isRefetching,
      isFetchingNextPage:
        mode === "infinite"
          ? infiniteQuery.isFetchingNextPage
          : loadingState.isFetchingNextPage,
      density,
      setDensity,
      globalFilter: filteringHook.globalFilter,
      setGlobalFilter: filteringHook.setGlobalFilter,
      tableContainerRef,
      features,
      mode,
      slots,
      onRefresh,
      handleExpand: handleExpand as (
        row: import("@tanstack/react-table").Row<GridRow>
      ) => Promise<void>,
      loadingRowIds,
      rowVirtualizer,
      columnVirtualizer,
      activeEdit: editingHook.activeEdit,
      startEditing: editingHook.startEditing,
      cancelEditing: editingHook.cancelEditing,
      commitEditing: editingHook.commitEditing,
      mutatingRowIds: editingHook.mutatingRowIds,
      errorRowIds: editingHook.errorRowIds,
      // Pagination
      pagination,
      setPagination,
      paginatedTotal: paginatedQuery.data?.total,
      // Infinite
      hasNextPage: infiniteQuery.hasNextPage,
      fetchNextPage: infiniteQuery.fetchNextPage,
    }),
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [
      table,
      isLoading,
      loadingState.isRefetching,
      loadingState.isFetchingNextPage,
      mode,
      infiniteQuery.isFetchingNextPage,
      infiniteQuery.hasNextPage,
      infiniteQuery.fetchNextPage,
      density,
      setDensity,
      filteringHook.globalFilter,
      filteringHook.setGlobalFilter,
      tableContainerRef,
      features,
      slots,
      onRefresh,
      handleExpand,
      loadingRowIds,
      rowVirtualizer,
      columnVirtualizer,
      editingHook.activeEdit,
      editingHook.startEditing,
      editingHook.cancelEditing,
      editingHook.commitEditing,
      editingHook.mutatingRowIds,
      editingHook.errorRowIds,
      pagination,
      setPagination,
      paginatedQuery.data?.total,
      orderingHook.columnOrder,
      columnPinningHook.columnPinning,
      groupingHook.grouping,
      groupingHook.expanded,
    ]
  )
}

import { useInfiniteQuery } from "@tanstack/react-query"
import { useMemo } from "react"
import type { QueryKey } from "@tanstack/react-query"
import type { SortState } from "@/components/data-grid/types/sort-types"
import type { FilterState } from "@/components/data-grid/types/filter-types"
import type { GridRow } from "@/components/data-grid/types/grid-types"

export interface InfinitePageResult<TData> {
  rows: TData[]
  nextPage: number | null
  total?: number
}

interface InfiniteDataConfig<TData> {
  queryKey: QueryKey
  queryFn: (params: {
    pageParam: number
    sort: SortState[]
    filters: FilterState[]
  }) => Promise<InfinitePageResult<TData>>
  sortState: SortState[]
  filterState: FilterState[]
  enabled?: boolean
}

export function useInfiniteData<TData extends GridRow>(
  config: InfiniteDataConfig<TData>,
) {
  const query = useInfiniteQuery({
    queryKey: [
      ...config.queryKey,
      { sort: config.sortState, filters: config.filterState },
    ],
    queryFn: ({ pageParam = 0 }) =>
      config.queryFn({
        pageParam: pageParam as number,
        sort: config.sortState,
        filters: config.filterState,
      }),
    initialPageParam: 0,
    getNextPageParam: (lastPage) => lastPage.nextPage ?? undefined,
    enabled: config.enabled !== false,
  })

  const rows = useMemo(
    () => query.data?.pages.flatMap((page) => page.rows) ?? [],
    [query.data],
  )

  return {
    rows,
    total: query.data?.pages[0]?.total,
    isLoading: query.isLoading,
    isFetchingNextPage: query.isFetchingNextPage,
    hasNextPage: query.hasNextPage,
    fetchNextPage: query.fetchNextPage,
    refetch: query.refetch,
    isRefetching: query.isRefetching,
    isError: query.isError,
    error: query.error,
  }
}

import { evaluateRowExpr, evaluateSourceExpr } from "./jsonata-evaluator"
import type { DataSourceConfig, SourceMap } from "./types"

// ─── Types ────────────────────────────────────────────────────────────────────

export interface FetchResult {
  data: unknown
  error: Error | null
}

// ─── URL Builder ─────────────────────────────────────────────────────────────

/**
 * Build the final request URL from a source's url field.
 * If the url contains JSONata (detected by presence of $ or operator chars),
 * it is evaluated with $sources context. Plain URLs are returned as-is.
 * Query params (already plain strings) are appended after URL construction.
 */
export async function buildRequestUrl(
  urlExpr: string,
  sources: SourceMap,
  params?: Record<string, string>
): Promise<string> {
  let url: string

  // Heuristic: if url contains JSONata chars, evaluate it; otherwise use as-is.
  // JSONata expressions typically contain $, &, (, ), or spaces.
  const looksLikeExpression = /[$&()"']/.test(urlExpr)

  if (looksLikeExpression) {
    const evaluated = await evaluateSourceExpr(urlExpr, { sources })
    url = String(evaluated ?? urlExpr)
  } else {
    url = urlExpr
  }

  if (params && Object.keys(params).length > 0) {
    const qs = new URLSearchParams(params).toString()
    url = url.includes("?") ? `${url}&${qs}` : `${url}?${qs}`
  }

  return url
}

// ─── Single Source Fetch ──────────────────────────────────────────────────────

/**
 * Execute one DataSourceConfig fetch with retry on network error and optional
 * transform applied to the raw response.
 *
 * - Network errors (TypeError from fetch) trigger 1 retry if retryOnNetworkError !== false.
 * - HTTP errors (non-ok status) are NOT retried — returned as { data: null, error }.
 * - Transform JSONata is applied to the raw parsed response if configured.
 * - Never throws — errors are returned as values.
 */
export async function fetchSource(
  source: DataSourceConfig,
  resolvedSources: SourceMap,
  signal?: AbortSignal
): Promise<FetchResult> {
  const url = await buildRequestUrl(
    source.url,
    resolvedSources,
    source.params
  )

  const headers: Record<string, string> = {
    "Content-Type": "application/json",
    ...source.headers,
  }

  const init: RequestInit = {
    method: source.method ?? "GET",
    headers,
    signal,
    ...(source.body ? { body: JSON.stringify(source.body) } : {}),
  }

  const shouldRetry = source.retryOnNetworkError !== false
  const maxAttempts = shouldRetry ? 2 : 1

  for (let attempt = 0; attempt < maxAttempts; attempt++) {
    try {
      const response = await fetch(url, init)

      if (!response.ok) {
        return {
          data: null,
          error: new Error(
            `HTTP ${response.status} ${response.statusText} — ${source.id}: ${url}`
          ),
        }
      }

      const raw = await response.json()

      // Apply JSONata transform if configured
      const data = source.transform
        ? await evaluateSourceExpr(
            source.transform,
            {
              sources: { ...resolvedSources, [source.id]: raw },
            },
            raw
          )
        : raw

      return { data, error: null }
    } catch (err) {
      const isLastAttempt = attempt === maxAttempts - 1
      const isAbort = err instanceof DOMException && err.name === "AbortError"

      if (isAbort || isLastAttempt) {
        return {
          data: null,
          error: err instanceof Error ? err : new Error(String(err)),
        }
      }
      // Continue to next attempt
    }
  }

  // Unreachable but satisfies TypeScript
  return { data: null, error: new Error(`fetchSource: unexpected exit for ${source.id}`) }
}

// ─── Row-Level Source Fetch ───────────────────────────────────────────────────

/**
 * Execute a row-level DataSourceConfig for one row with cacheKey-based deduplication.
 *
 * All rows with the same cacheKey value share one in-flight Promise stored in dedupeMap.
 * The dedupeMap is owned by the caller (useTableEngine) and cleared on refetch.
 *
 * @returns FetchResult — never throws. On error: { data: null, error }.
 */
export async function fetchRowLevelSource(
  source: DataSourceConfig,
  row: Record<string, unknown>,
  resolvedSources: SourceMap,
  dedupeMap: Map<string, Promise<FetchResult>>,
  signal?: AbortSignal
): Promise<FetchResult> {
  // Compute the cache key for this row
  let cacheKey: string

  if (source.cacheKey) {
    try {
      const keyValue = await evaluateRowExpr(source.cacheKey, { row })
      cacheKey = `${source.id}::${String(keyValue ?? "")}`
    } catch {
      // If cacheKey evaluation fails, use a unique key (no dedup for this row)
      cacheKey = `${source.id}::${Math.random()}`
    }
  } else {
    // No cacheKey — always fetch independently (no dedup)
    return fetchSource(source, resolvedSources, signal)
  }

  // Return existing in-flight promise if one exists for this cacheKey
  if (dedupeMap.has(cacheKey)) {
    return dedupeMap.get(cacheKey)!
  }

  // Start new fetch and register in dedup map
  const promise = fetchSource(source, resolvedSources, signal)
  dedupeMap.set(cacheKey, promise)
  return promise
}

import { booleanColumn } from "@/components/data-grid/columns/boolean-column"
import { codeColumn } from "@/components/data-grid/columns/code-column"
import { dateColumn } from "@/components/data-grid/columns/date-column"
import { multiValueColumn } from "@/components/data-grid/columns/multi-value-column"
import { numberColumn } from "@/components/data-grid/columns/number-column"
import { selectColumn } from "@/components/data-grid/columns/select-column"
import { stringColumn } from "@/components/data-grid/columns/string-column"
import type { GridColumnDef } from "@/components/data-grid/types/column-types"
import type { GridRow } from "@/components/data-grid/types/grid-types"
import { evaluateDepthRule } from "./jsonata-evaluator"
import {
  ConfigError,
  type ColumnBuildResult,
  type ColumnConfig,
  type DepthRule,
  type SourceMap,
  type TableColumnMeta,
  type TableFeaturesConfig,
} from "./types"

// ─── Factory Registry ─────────────────────────────────────────────────────────
//
// To add a new column type, add an entry here.
// Each factory accepts { accessorKey, header, ...rest } and returns GridColumnDef.

type FactoryOptions = {
  accessorKey: string
  header: string
  editable?: boolean
  copyable?: boolean
  width?: number
  minWidth?: number
  maxWidth?: number
  meta?: Record<string, unknown>
  [key: string]: unknown
}

type ColumnFactory = (options: FactoryOptions) => GridColumnDef

const FACTORY_REGISTRY: Record<string, ColumnFactory> = {
  string: stringColumn as ColumnFactory,
  number: numberColumn as ColumnFactory,
  date: dateColumn as ColumnFactory,
  "multi-value": multiValueColumn as ColumnFactory,
  select: selectColumn as ColumnFactory,
  boolean: booleanColumn as ColumnFactory,
  code: codeColumn as ColumnFactory,
}

function getFactory(type: string | undefined): ColumnFactory {
  return FACTORY_REGISTRY[type ?? "string"] ?? FACTORY_REGISTRY["string"]
}

// ─── Depth Rule Resolver ──────────────────────────────────────────────────────

function buildEditableFn(
  rule: DepthRule
): (row: GridRow, depth: number) => boolean {
  return (_row, depth) => evaluateDepthRule(rule, depth)
}

// ─── Secondary Source Join ────────────────────────────────────────────────────

/**
 * Build an index map from sourceKey value → source record for O(1) joins.
 */
function buildJoinIndex(
  sourceData: unknown,
  sourceKey: string
): Map<unknown, Record<string, unknown>> {
  if (!Array.isArray(sourceData)) return new Map()
  const index = new Map<unknown, Record<string, unknown>>()
  for (const record of sourceData) {
    if (record && typeof record === "object") {
      const key = (record as Record<string, unknown>)[sourceKey]
      index.set(key, record as Record<string, unknown>)
    }
  }
  return index
}

// ─── Main Build Function ──────────────────────────────────────────────────────

/**
 * Convert ColumnConfig[] into GridColumnDef[] using the existing column factories.
 *
 * Extensibility:
 * - Add a new ColumnType: register a factory in FACTORY_REGISTRY above.
 * - Add a new per-column flag: add the mapping in the flag application section below.
 *
 * @param columns  - The ColumnConfig array from TableConfig.
 * @param features - TableFeaturesConfig for reading global enable/disable defaults.
 * @param sourceMap - The resolved SourceMap (from DAG executor) for join columns.
 * @returns columns (GridColumnDef[]) and initialColumnVisibility (hidden columns map).
 */
export function buildColumns<TData extends GridRow>(
  columns: ColumnConfig[],
  features: TableFeaturesConfig | undefined,
  sourceMap: SourceMap
): ColumnBuildResult<TData> {
  const initialColumnVisibility: Record<string, boolean> = {}
  const builtColumns: GridColumnDef<TData>[] = []

  // Global feature defaults (columns inherit these unless overridden per-column)
  const globalSortingEnabled = features?.sorting?.enabled ?? true
  const globalFilteringEnabled = features?.filtering?.enabled ?? true
  const globalResizingEnabled = features?.columnResizing?.enabled ?? true

  for (const colConfig of columns) {
    const {
      field,
      header,
      type,
      visible,
      width,
      minWidth,
      maxWidth,
      sortable,
      filterable,
      resizable,
      orderable,
      editable,
      copyable,
      dataSource,
      joinOn,
      // valueExpr: _valueExpr, // pre-populated by engine onto row[field] — no builder action needed
      meta: extraMeta,
      pinned,
    } = colConfig

    // ── Visibility ──────────────────────────────────────────────────────────
    if (visible === false) {
      initialColumnVisibility[field] = false
    }

    // ── Editable / DepthRule ────────────────────────────────────────────────
    let resolvedEditable = false
    let editableFn: TableColumnMeta["editableFn"] | undefined

    if (typeof editable === "boolean") {
      resolvedEditable = editable
    } else if (editable !== undefined) {
      resolvedEditable = false
      editableFn = buildEditableFn(editable)
    }

    // ── Build meta ──────────────────────────────────────────────────────────
    const meta: TableColumnMeta = {
      ...(extraMeta as Partial<TableColumnMeta>),
      editable: resolvedEditable,
      ...(editableFn ? { editableFn } : {}),
      ...(copyable !== undefined ? { copyable } : {}),
      ...(orderable === false ? { orderable: false } : {}),
      ...(pinned ? { pinned } : {}),
    }

    // ── Select factory and build base column def ────────────────────────────
    const factory = getFactory(type)
    const factoryOptions: FactoryOptions = {
      accessorKey: field,
      header,
      editable: resolvedEditable,
      copyable: copyable ?? false,
      // Pass width/minWidth/maxWidth as the factories expect (they map to size/minSize internally)
      ...(width !== undefined ? { width } : {}),
      ...(minWidth !== undefined ? { minWidth } : {}),
      ...(maxWidth !== undefined ? { maxWidth } : {}),
      meta,
      ...(type === "select" && extraMeta?.options
        ? { options: extraMeta.options }
        : {}),
    }

    let colDef = factory(factoryOptions) as GridColumnDef<TData>

    // ── Apply per-column feature flag overrides ─────────────────────────────
    if (
      sortable === false ||
      (sortable === undefined && !globalSortingEnabled)
    ) {
      colDef = { ...colDef, enableSorting: false }
    } else if (sortable === true) {
      colDef = { ...colDef, enableSorting: true }
    }

    if (
      filterable === false ||
      (filterable === undefined && !globalFilteringEnabled)
    ) {
      colDef = { ...colDef, enableColumnFilter: false }
    } else if (filterable === true) {
      colDef = { ...colDef, enableColumnFilter: true }
    }

    if (
      resizable === false ||
      (resizable === undefined && !globalResizingEnabled)
    ) {
      colDef = { ...colDef, enableResizing: false }
    } else if (resizable === true) {
      colDef = { ...colDef, enableResizing: true }
    }

    // ── Secondary source join (accessorFn) ──────────────────────────────────
    // joinOn.sourceKey = PK field on source record used to build the index
    // joinOn.rowField  = FK field on the primary row for lookup
    // joinOn.sourceField = display field on the matched source record
    if (dataSource && !joinOn) {
      throw new ConfigError(
        `Column "${field}" has dataSource "${dataSource}" but no joinOn config. ` +
          `Provide joinOn: { rowField, sourceKey, sourceField } to define the join.`
      )
    }

    if (dataSource && joinOn) {
      const rawSourceData = sourceMap[dataSource]
      const joinIndex = buildJoinIndex(rawSourceData, joinOn.sourceKey)

      // eslint-disable-next-line @typescript-eslint/no-unused-vars
      const { accessorKey: _removed, ...colDefWithoutKey } =
        colDef as typeof colDef & { accessorKey?: string }
      colDef = {
        ...colDefWithoutKey,
        id: field,
        accessorFn: (row: TData) => {
          const fkValue = (row as Record<string, unknown>)[joinOn.rowField]
          const record = joinIndex.get(fkValue)
          return record ? (record[joinOn.sourceField] ?? null) : null
        },
      } as GridColumnDef<TData>
    }

    // ── valueExpr: accessorKey already points to field (engine pre-populates) ─
    // No special handling needed — factory set accessorKey = field.

    builtColumns.push(colDef)
  }

  return { columns: builtColumns, initialColumnVisibility }
}

import { buildWaves } from "./dag-resolver"
import { ConfigError } from "./types"
import type { TableConfig } from "./types"

/**
 * Validates a TableConfig at hook-mount time (before any fetch).
 * Throws ConfigError with a descriptive message on the first problem found.
 * This keeps all validation in one place and makes errors easy to find.
 */
export function validateConfig(config: TableConfig): void {
  if (!config.id?.trim()) {
    throw new ConfigError("TableConfig.id is required and must be a non-empty string.")
  }

  if (!config.dataSources || config.dataSources.length === 0) {
    throw new ConfigError(
      `TableConfig "${config.id}": dataSources must contain at least one entry.`
    )
  }

  if (!config.columns || config.columns.length === 0) {
    throw new ConfigError(
      `TableConfig "${config.id}": columns must contain at least one entry.`
    )
  }

  // Validate rowLevel sources have a cacheKey
  const sourceIds = new Set(config.dataSources.map((s) => s.id))
  for (const source of config.dataSources) {
    if (source.rowLevel && !source.cacheKey) {
      throw new ConfigError(
        `DataSource "${source.id}" has rowLevel:true but no cacheKey. ` +
          `Provide a JSONata cacheKey expression (e.g. "$string(supplierId)") to deduplicate row-level calls.`
      )
    }
  }

  // Validate column dataSource references point to known sources
  for (const col of config.columns) {
    if (col.dataSource && !sourceIds.has(col.dataSource)) {
      throw new ConfigError(
        `Column "${col.field}" references unknown dataSource "${col.dataSource}". ` +
          `Available source ids: ${[...sourceIds].join(", ")}`
      )
    }
  }

  // Validate DAG (circular deps, unknown dep ids) — buildWaves throws ConfigError
  buildWaves(config.dataSources)
}

import { DataGrid } from "@/components/data-grid/data-grid"
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert"
import type { GridRow } from "@/components/data-grid/types/grid-types"
import type { TableConfig } from "./types"
import { useTableEngine } from "./use-table-engine"

export interface ConfiguredTableProps {
  config: TableConfig
  className?: string
}

/**
 * Declarative table component. Pass a TableConfig and get a fully-featured DataGrid.
 *
 * Handles:
 * - Multi-source API fetching with DAG-based dependency resolution
 * - JSONata data transforms and derived column values
 * - Per-column visibility, sorting, filtering, editing, resizing, and ordering control
 * - Flat, Paginated, Infinite, and Tree modes
 *
 * @example
 * <ConfiguredTable config={bomTableConfig} />
 */
export function ConfiguredTable({ config, className }: ConfiguredTableProps) {
  const {
    data,
    columns,
    initialColumnVisibility,
    isLoading,
    isError,
    error,
    isFetchingNextPage,
  } = useTableEngine<GridRow>(config)

  if (isError) {
    return (
      <Alert variant="destructive" className="m-4">
        <AlertTitle>Failed to load table</AlertTitle>
        <AlertDescription>
          {error?.message ?? "An unexpected error occurred."}
        </AlertDescription>
      </Alert>
    )
  }

  return (
    <DataGrid
      data={data}
      columns={columns}
      mode={config.mode}
      features={config.features ?? {}}
      isLoading={isLoading}
      initialColumnVisibility={initialColumnVisibility}
      getSubRows={
        config.options?.subRowsField
          ? (row) =>
              (row as Record<string, unknown>)[
                config.options!.subRowsField!
              ] as GridRow[] | undefined
          : undefined
      }
      isFetchingNextPage={isFetchingNextPage}
      className={className}
    />
  )
}

import type { DataSourceConfig, SourceMap } from "./types"
import { ConfigError } from "./types"

// ─── Types ────────────────────────────────────────────────────────────────────

/** A wave is a list of source IDs that can all execute in parallel. */
export type Wave = string[]

/**
 * Function that executes a single source given its ID and all prior resolved sources.
 * The DAG executor calls this for every node; the caller provides the actual fetch logic.
 */
export type SourceExecutorFn = (
  sourceId: string,
  resolvedSources: SourceMap,
  signal?: AbortSignal
) => Promise<unknown>

// ─── Graph Building ───────────────────────────────────────────────────────────

/**
 * Validate dependency references and build adjacency structures.
 * Throws ConfigError if any dependsOn references an unknown source id.
 */
function buildGraph(sources: DataSourceConfig[]): {
  inDegree: Map<string, number>
  dependents: Map<string, string[]>
} {
  const ids = new Set(sources.map((s) => s.id))

  // Validate all deps reference known ids and contain no duplicates
  for (const source of sources) {
    const seen = new Set<string>()
    for (const dep of source.dependsOn ?? []) {
      if (!ids.has(dep)) {
        throw new ConfigError(
          `DataSource "${source.id}" depends on unknown source "${dep}". ` +
            `Available ids: ${[...ids].join(", ")}`
        )
      }
      if (dep === source.id) {
        throw new ConfigError(
          `DataSource "${source.id}" has a self-dependency.`
        )
      }
      if (seen.has(dep)) {
        throw new ConfigError(
          `DataSource "${source.id}" has a duplicate dependency on "${dep}".`
        )
      }
      seen.add(dep)
    }
  }

  // Build in-degree map and reverse adjacency (who depends on me?)
  const inDegree = new Map<string, number>()
  const dependents = new Map<string, string[]>()

  for (const source of sources) {
    inDegree.set(source.id, source.dependsOn?.length ?? 0)
    dependents.set(source.id, [])
  }

  for (const source of sources) {
    for (const dep of source.dependsOn ?? []) {
      dependents.get(dep)!.push(source.id)
    }
  }

  return { inDegree, dependents }
}

// ─── Kahn's Algorithm ─────────────────────────────────────────────────────────

/**
 * Topologically sort DataSourceConfig[] into ordered waves using Kahn's algorithm.
 *
 * - Sources with no dependencies go into Wave 0.
 * - When a wave completes, nodes whose in-degree drops to 0 form the next wave.
 * - If nodes remain after the algorithm (cycle detected), throws ConfigError.
 *
 * @throws ConfigError on circular dependencies or unknown dependency ids.
 * @returns Ordered array of waves; each wave is a list of source IDs to run in parallel.
 */
export function buildWaves(sources: DataSourceConfig[]): Wave[] {
  if (sources.length === 0) return []

  const { inDegree, dependents } = buildGraph(sources)
  const waves: Wave[] = []
  const remaining = new Set(inDegree.keys())

  while (remaining.size > 0) {
    // Find all nodes with in-degree 0 (ready to execute)
    const wave: string[] = []
    for (const id of remaining) {
      if (inDegree.get(id) === 0) wave.push(id)
    }

    if (wave.length === 0) {
      // Nodes remain but none have in-degree 0 — circular dependency
      const cycleNodes = [...remaining]
      throw new ConfigError(
        `Circular dependency detected among DataSources: ${cycleNodes.join(", ")}. ` +
          `Check the dependsOn fields for a cycle.`
      )
    }

    waves.push(wave)

    // Remove this wave's nodes and decrement in-degrees of their dependents
    for (const id of wave) {
      remaining.delete(id)
      for (const dependent of dependents.get(id) ?? []) {
        inDegree.set(dependent, (inDegree.get(dependent) ?? 0) - 1)
      }
    }
  }

  return waves
}

// ─── Wave Executor ────────────────────────────────────────────────────────────

/**
 * Execute a list of waves in order. Within each wave, all sources run in parallel
 * via Promise.all. Between waves, execution is sequential (next wave waits for previous).
 *
 * Each call to executeFn receives:
 * - The source ID
 * - All sources resolved so far (accumulated across prior waves)
 * - An optional AbortSignal
 *
 * @returns A SourceMap: { [sourceId]: resolvedData }
 */
export async function executeWaves(
  waves: Wave[],
  executeFn: SourceExecutorFn,
  signal?: AbortSignal
): Promise<SourceMap> {
  const resolved: SourceMap = {}

  for (const wave of waves) {
    // All sources in this wave run in parallel with a snapshot of resolved so far
    const waveResults = await Promise.all(
      wave.map(async (id) => {
        const data = await executeFn(id, { ...resolved }, signal)
        return { id, data }
      })
    )

    // Merge wave results into resolved map for the next wave
    for (const { id, data } of waveResults) {
      resolved[id] = data
    }
  }

  return resolved
}

import jsonata from "jsonata"
import type { DepthRule, SourceMap } from "./types"

// ─── Context types ────────────────────────────────────────────────────────────

export interface SourceEvalContext {
  /** All resolved source data, accessible as $sources.<id> in expressions. */
  sources: SourceMap
}

export interface RowEvalContext {
  /** The current row object, accessible as $row in expressions. */
  row: Record<string, unknown>
}

// ─── Source mode ─────────────────────────────────────────────────────────────

/**
 * Evaluate a JSONata expression in "source" mode.
 *
 * The input document is set to the first source's data (enabling `$.field`
 * path expressions on the primary source). The full source map is also
 * available as the `$sources` binding for cross-source references.
 *
 * Available bindings: $sources (the resolved source map).
 * Used for: transform, url, params, body expressions.
 *
 * @returns The evaluated result, or undefined if expression is empty.
 * @throws With expression string + context appended on evaluation error.
 */
export async function evaluateSourceExpr(
  expression: string,
  context: SourceEvalContext,
  inputDoc?: unknown
): Promise<unknown> {
  if (!expression.trim()) return undefined

  try {
    const expr = jsonata(expression)
    // Use provided inputDoc, or fall back to the first source's data
    const effectiveInput =
      inputDoc !== undefined
        ? inputDoc
        : (Object.values(context.sources)[0] ?? {})

    // JSONata bindings use keys WITHOUT the leading "$": key "sources" → $sources in expressions.
    const result = await expr.evaluate(effectiveInput, {
      sources: context.sources,
    })
    return result
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err)
    throw new Error(
      `JSONata source expression failed: ${msg}\nExpression: ${expression}`
    )
  }
}

// ─── Row mode ─────────────────────────────────────────────────────────────────

/**
 * Evaluate a JSONata expression in "row" mode.
 * Available bindings: $row (the current row object).
 * Used for: valueExpr derived column computation.
 *
 * @returns The evaluated result, or undefined if expression is empty.
 */
export async function evaluateRowExpr(
  expression: string,
  context: RowEvalContext
): Promise<unknown> {
  if (!expression.trim()) return undefined

  try {
    const expr = jsonata(expression)
    const result = await expr.evaluate({}, { row: context.row })
    return result
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err)
    throw new Error(
      `JSONata row expression failed: ${msg}\nExpression: ${expression}\nRow: ${JSON.stringify(context.row)}`
    )
  }
}

// ─── Depth rule (synchronous — no JSONata needed) ─────────────────────────────

/**
 * Evaluate a DepthRule synchronously against a tree node's depth.
 * This is pure boolean logic — no JSONata involved.
 * Used by column-builder to produce the editableFn stored on TableColumnMeta.
 */
export function evaluateDepthRule(rule: DepthRule, depth: number): boolean {
  if ("depths" in rule) return rule.depths.includes(depth)
  if ("minDepth" in rule) return depth >= rule.minDepth
  if ("maxDepth" in rule) return depth <= rule.maxDepth
  return false
}

import type { GridRow, GridFeaturesConfig, GridMode } from "@/components/data-grid/types/grid-types"
import type { ColumnType, ColumnMeta, GridColumnDef } from "@/components/data-grid/types/column-types"

// ─── Error ────────────────────────────────────────────────────────────────────

/**
 * Thrown when a TableConfig is structurally invalid (cycles, unknown refs, etc.)
 * Caught at hook-mount time before any fetch is made.
 */
export class ConfigError extends Error {
  constructor(message: string) {
    super(message)
    this.name = "ConfigError"
  }
}

// ─── Data Source ──────────────────────────────────────────────────────────────

/**
 * Describes one API call in the data dependency graph.
 * `dependsOn` drives the DAG — sources with no deps run first (Wave 0),
 * sources that depend on others run in the next available wave.
 */
export interface DataSourceConfig {
  /** Unique identifier used to reference this source in other configs and JSONata via $sources.<id> */
  id: string
  /**
   * The endpoint URL. May be a plain string or a JSONata expression.
   * In JSONata context: $sources.<id> references resolved prior source data.
   * Example: '"/api/suppliers?ids=" & $join($distinct($sources.bom.supplierId), ",")'
   */
  url: string
  /** HTTP method. Defaults to "GET". */
  method?: "GET" | "POST"
  /** Static headers merged with any global headers. */
  headers?: Record<string, string>
  /**
   * Query params. Each value may be a plain string or a JSONata expression
   * evaluated with $sources context.
   */
  params?: Record<string, string>
  /**
   * Request body for POST requests. May reference $sources via JSONata expressions
   * embedded in string values.
   */
  body?: Record<string, unknown>
  /**
   * IDs of other DataSourceConfig entries this source depends on.
   * The DAG resolver guarantees those sources are resolved first.
   * Circular dependencies throw ConfigError at hook-mount time.
   */
  dependsOn?: string[]
  /**
   * JSONata expression applied to the raw API response to produce the final data.
   * Example: "$.items" extracts the items array from { items: [...] }.
   * If omitted, the raw response is used as-is.
   */
  transform?: string
  /**
   * If true, this source is called once per unique cacheKey value across all rows
   * rather than as a single bulk call. Used for column enrichment (FK lookups).
   */
  rowLevel?: boolean
  /**
   * JSONata expression evaluated on each row to produce a string cache key.
   * Rows with the same cacheKey share one fetch call (deduplication).
   * Required when rowLevel is true.
   * Example: "$string(supplierId)"
   */
  cacheKey?: string
  /** Whether to retry once on network error. Defaults to true. 4xx/5xx are NOT retried. */
  retryOnNetworkError?: boolean
}

// ─── Depth Rule ───────────────────────────────────────────────────────────────

/**
 * Controls editability at specific tree depths.
 * Depth 0 = root rows, depth 1 = their children, etc.
 *
 * @example
 * // Editable only at depth 1 and 2
 * { depths: [1, 2] }
 *
 * // Editable from depth 1 downward (leaf rows only when root is not editable)
 * { minDepth: 1 }
 *
 * // Editable only at root level
 * { maxDepth: 0 }
 */
export type DepthRule =
  | { depths: number[] }
  | { minDepth: number }
  | { maxDepth: number }

// ─── Column Config ────────────────────────────────────────────────────────────

/**
 * Declarative column definition. The column builder maps this to a GridColumnDef
 * using the appropriate existing column factory.
 */
export interface ColumnConfig {
  /** Maps to accessorKey on the produced GridColumnDef. */
  field: string
  /** Column header label. */
  header: string

  // Type — drives factory selection in column-builder
  /** Column data type. Drives which existing factory is used. Defaults to "string". */
  type?: ColumnType

  // Visibility & layout
  /** Whether the column is visible on mount. Defaults to true. */
  visible?: boolean
  /** Initial width in pixels. */
  width?: number
  /** Minimum width in pixels. */
  minWidth?: number
  /** Maximum width in pixels. */
  maxWidth?: number
  /** Pin the column to the left or right. */
  pinned?: "left" | "right" | false

  // Per-column feature toggles
  /** Allow sorting by this column. Defaults to global features.sorting.enabled. */
  sortable?: boolean
  /** Show filter UI for this column. Defaults to global features.filtering.enabled. */
  filterable?: boolean
  /** Allow column to be resized by dragging. Defaults to global features.columnResizing.enabled. */
  resizable?: boolean
  /**
   * Allow this column to be reordered via drag-and-drop.
   * When false, the drag handle is hidden and the column stays in place.
   * Defaults to true.
   */
  orderable?: boolean
  /** Show copy-to-clipboard button on hover. */
  copyable?: boolean

  /**
   * Editability control.
   * - boolean: editable everywhere or nowhere.
   * - DepthRule: editable only at specific tree depths (tree mode only).
   */
  editable?: boolean | DepthRule

  // Secondary source binding
  /** ID of a DataSourceConfig that provides the value for this column. */
  dataSource?: string
  /**
   * When dataSource is set, defines how to join the secondary source
   * data to the primary row.
   */
  joinOn?: {
    /** Field on the primary row used as the FK (e.g. "supplierId"). */
    rowField: string
    /**
     * Field on the source record to match against rowField value (the PK / join key).
     * Example: "id" — find the source record where record.id === row.supplierId.
     */
    sourceKey: string
    /**
     * Field on the matched source record to use as this column's cell value.
     * Example: "name" — display supplier.name after joining on supplier.id.
     */
    sourceField: string
  }

  /**
   * JSONata expression to compute a derived value from the current row.
   * Context: $row = the current row object.
   * Evaluated during data resolution phase; result stored on row[field] before
   * TanStack Table renders — so accessorKey reads a plain pre-computed value.
   * Example: "$row.quantity * $row.unitPrice"
   */
  valueExpr?: string

  /** Direct pass-through to ColumnMeta on the produced GridColumnDef. */
  meta?: Partial<ColumnMeta>
}

// ─── Table Features ───────────────────────────────────────────────────────────

/**
 * Superset of GridFeaturesConfig. The three new fields are engine-only:
 * they are consumed by column-builder.ts and stripped before being passed
 * to DataGrid (which only accepts GridFeaturesConfig).
 */
export interface TableFeaturesConfig extends GridFeaturesConfig {
  /** Enable/disable global drag-and-drop column reordering. */
  columnOrdering?: { enabled?: boolean }
  /** Enable/disable global column resize handles. */
  columnResizing?: { enabled?: boolean }
  /** Enable/disable the show/hide columns UI in the toolbar. */
  columnVisibility?: { enabled?: boolean }
}

// ─── Table Config ─────────────────────────────────────────────────────────────

/**
 * The top-level config object a developer writes to declare a table.
 * Pass to <ConfiguredTable config={myConfig} /> or useTableEngine(myConfig).
 */
export interface TableConfig {
  /** Unique identifier for this table. Used as the base React Query key. */
  id: string
  /** Grid rendering mode. */
  mode: GridMode
  /**
   * All API data sources for this table. Evaluated in DAG order.
   * The first non-rowLevel source without dependsOn provides the primary rows.
   */
  dataSources: DataSourceConfig[]
  /** Column definitions. Mapped to GridColumnDef[] by column-builder. */
  columns: ColumnConfig[]
  /** Feature flags. Engine-only keys (columnOrdering/Resizing/Visibility) are stripped before passing to DataGrid. */
  features?: TableFeaturesConfig
  options?: {
    /** Initial page size for paginated mode. Defaults to 50. */
    pageSize?: number
    /** Row height override passed to virtualization. */
    rowHeight?: number
    /**
     * Field name on row objects that contains the children array (tree mode).
     * Plain string — not a JSONata expression.
     * Example: "children"
     */
    subRowsField?: string
  }
}

// ─── Extended Column Meta ─────────────────────────────────────────────────────

/**
 * Engine-internal extension of ColumnMeta.
 * Carries the runtime editability resolver for DepthRule columns.
 * ColumnMeta already has [key: string]: unknown so this is type-safe as a cast.
 */
export interface TableColumnMeta extends ColumnMeta {
  /**
   * When editable is a DepthRule, column-builder stores the resolver here
   * and sets meta.editable = false. Checked at render time using row.depth.
   */
  editableFn?: (row: GridRow, depth: number) => boolean
  /**
   * When orderable: false, column-builder stores false here.
   * DataGridHeader reads this to suppress the drag handle affordance.
   */
  orderable?: boolean
}

// ─── Engine Result ────────────────────────────────────────────────────────────

/**
 * Return type of useTableEngine. Ready to be spread onto DataGrid props.
 */
export interface TableEngineResult<TData extends GridRow> {
  /** Resolved, merged, derived-value-enriched rows. */
  data: TData[]
  /** Built column defs using existing column factories. */
  columns: GridColumnDef<TData>[]
  /** Initial visibility state — columns with visible:false appear here as { field: false }. */
  initialColumnVisibility: Record<string, boolean>
  /** True while any primary source fetch is in-flight. */
  isLoading: boolean
  /** True if the primary DAG fetch threw an error. */
  isError: boolean
  /** The error from the primary DAG fetch, if any. */
  error: Error | null
  /** Trigger a full refetch of all sources. */
  refetch: () => void
  /** Errors from row-level source fetches (partial — other columns still render). */
  rowSourceErrors: Array<{ sourceId: string; cacheKey: string; error: Error }>
  // Infinite mode props (undefined in other modes)
  fetchNextPage?: () => void
  hasNextPage?: boolean
  isFetchingNextPage?: boolean
  // Paginated / total count
  total?: number
}

// ─── Column Build Result ──────────────────────────────────────────────────────

/** Internal return type of buildColumns() in column-builder.ts. */
export interface ColumnBuildResult<TData extends GridRow> {
  columns: GridColumnDef<TData>[]
  initialColumnVisibility: Record<string, boolean>
}

// ─── Source Map ───────────────────────────────────────────────────────────────

/** Map produced by the DAG resolver: sourceId → transformed response data. */
export type SourceMap = Record<string, unknown>

import { useInfiniteData } from "@/components/data-grid/hooks/use-infinite-data"
import type { GridRow } from "@/components/data-grid/types/grid-types"
import { keepPreviousData, useQuery } from "@tanstack/react-query"
import React from "react"
import { fetchSource, type FetchResult } from "./api-executor"
import { buildColumns } from "./column-builder"
import { validateConfig } from "./config-validator"
import { buildWaves, executeWaves } from "./dag-resolver"
import { evaluateRowExpr } from "./jsonata-evaluator"
import type {
  DataSourceConfig,
  SourceMap,
  TableConfig,
  TableEngineResult,
} from "./types"

// Re-export FetchResult for convenience
export type { FetchResult }

// ─── Source Executor ──────────────────────────────────────────────────────────

/**
 * Creates the executeFn for executeWaves — handles building the final URL/body
 * from prior $sources context and calling fetchSource.
 */
function createSourceExecutor(
  sources: DataSourceConfig[],
  signal?: AbortSignal
) {
  const sourceMap = new Map(sources.map((s) => [s.id, s]))

  return async (id: string, resolvedSources: SourceMap): Promise<unknown> => {
    const source = sourceMap.get(id)
    if (!source) throw new Error(`Unknown source id: ${id}`)

    const result = await fetchSource(source, resolvedSources, signal)
    if (result.error) throw result.error
    return result.data
  }
}

// ─── Derived Value Computation ────────────────────────────────────────────────

/**
 * For all columns with valueExpr, evaluate the JSONata expression against each
 * row and write the result directly onto the row object at row[field].
 * Done in parallel across all rows for a given column.
 */
async function computeDerivedValues<TData extends GridRow>(
  rows: TData[],
  columns: TableConfig["columns"],
  subRowsField?: string
): Promise<TData[]> {
  const derivedCols = columns.filter((c) => c.valueExpr)
  // Even if no derived columns at this level, we might have children that need processing
  if (derivedCols.length === 0 && !subRowsField) return rows

  const enrichedRows = await Promise.all(
    rows.map(async (row) => {
      const enriched = { ...row }

      // 1. Compute derived values for current row
      if (derivedCols.length > 0) {
        await Promise.all(
          derivedCols.map(async (col) => {
            try {
              const value = await evaluateRowExpr(col.valueExpr!, {
                row: row as Record<string, unknown>,
              })
              ;(enriched as Record<string, unknown>)[col.field] = value
            } catch {
              ;(enriched as Record<string, unknown>)[col.field] = null
            }
          })
        )
      }

      // 2. Recursively process children if they exist
      if (
        subRowsField &&
        (row as Record<string, unknown>)[subRowsField] &&
        Array.isArray((row as Record<string, unknown>)[subRowsField])
      ) {
        ;(enriched as Record<string, unknown>)[subRowsField] =
          await computeDerivedValues(
            (row as Record<string, unknown>)[subRowsField] as TData[],
            columns,
            subRowsField
          )
      }

      return enriched
    })
  )

  return enrichedRows
}

// ─── Primary Data Resolution ──────────────────────────────────────────────────

/**
 * Resolves all non-rowLevel sources via the DAG executor.
 * Returns the full SourceMap and the primary rows array.
 * The "primary source" is the first non-rowLevel DataSourceConfig.
 */
async function resolvePrimaryData<TData extends GridRow>(
  config: TableConfig,
  signal?: AbortSignal
): Promise<{ sourceMap: SourceMap; rows: TData[] }> {
  const nonRowLevelSources = config.dataSources.filter((s) => !s.rowLevel)
  const waves = buildWaves(nonRowLevelSources)
  const executor = createSourceExecutor(nonRowLevelSources, signal)
  const sourceMap = await executeWaves(waves, executor, signal)

  // Primary source = first non-rowLevel source (by config order)
  const primarySourceId = nonRowLevelSources[0]?.id
  const rawRows = primarySourceId ? sourceMap[primarySourceId] : []
  const rows = Array.isArray(rawRows) ? (rawRows as TData[]) : []

  return { sourceMap, rows }
}

// ─── Row-Level Source Enrichment ──────────────────────────────────────────────

/**
 * For all rowLevel DataSourceConfigs, fetch enrichment data for each row
 * using cacheKey-based deduplication, then merge results into rows.
 * Errors from individual row fetches are collected, not re-thrown.
 */
async function enrichRowsWithRowLevelSources<TData extends GridRow>(
  rows: TData[],
  config: TableConfig,
  resolvedSources: SourceMap,
  signal?: AbortSignal
): Promise<{
  rows: TData[]
  rowSourceErrors: TableEngineResult<TData>["rowSourceErrors"]
}> {
  const rowLevelSources = config.dataSources.filter((s) => s.rowLevel)
  const subRowsField = config.options?.subRowsField
  const rowSourceErrors: TableEngineResult<TData>["rowSourceErrors"] = []

  // If no row-level sources AND no children to recurse into, just return
  if (rowLevelSources.length === 0 && !subRowsField) {
    return { rows, rowSourceErrors: [] }
  }

  const { fetchRowLevelSource } = await import("./api-executor")
  let processedRows = [...rows]

  // A. Process each row-level source for the current level
  for (const source of rowLevelSources) {
    const dedupeMap = new Map<
      string,
      Promise<{ data: unknown; error: Error | null }>
    >()
    const joinCols = config.columns.filter(
      (c) => c.dataSource === source.id && c.joinOn
    )
    if (joinCols.length === 0) continue

    const rowResults = await Promise.all(
      processedRows.map((row) =>
        fetchRowLevelSource(
          source,
          row as Record<string, unknown>,
          resolvedSources,
          dedupeMap,
          signal
        )
      )
    )

    processedRows = processedRows.map((row, idx) => {
      const { data, error } = rowResults[idx]
      if (error) {
        const cacheKey = source.cacheKey
          ? String((row as Record<string, unknown>)[source.cacheKey] ?? "")
          : String(idx)
        rowSourceErrors.push({ sourceId: source.id, cacheKey, error })
        return row
      }

      const enriched = { ...row }
      if (data && Array.isArray(data)) {
        for (const col of joinCols) {
          if (!col.joinOn) continue
          const match = (data as Record<string, unknown>[]).find(
            (r) =>
              r[col.joinOn!.sourceKey] ===
              (row as Record<string, unknown>)[col.joinOn!.rowField]
          )
          ;(enriched as Record<string, unknown>)[col.field] = match
            ? match[col.joinOn.sourceField]
            : null
        }
      }
      return enriched
    })
  }

  // B. Recursively enrich children if they exist
  if (subRowsField) {
    processedRows = await Promise.all(
      processedRows.map(async (row) => {
        const children = (row as Record<string, unknown>)[subRowsField]
        if (Array.isArray(children) && children.length > 0) {
          const { rows: enrichedChildren, rowSourceErrors: childErrors } =
            await enrichRowsWithRowLevelSources(
              children as TData[],
              config,
              resolvedSources,
              signal
            )
          rowSourceErrors.push(...childErrors)
          return { ...row, [subRowsField]: enrichedChildren }
        }
        return row
      })
    )
  }

  return { rows: processedRows, rowSourceErrors }
}

// ─── Full Resolution Pipeline ─────────────────────────────────────────────────

interface ResolvedData<TData extends GridRow> {
  rows: TData[]
  sourceMap: SourceMap
  rowSourceErrors: TableEngineResult<TData>["rowSourceErrors"]
}

async function resolveAll<TData extends GridRow>(
  config: TableConfig,
  signal?: AbortSignal
): Promise<ResolvedData<TData>> {
  const { sourceMap, rows: primaryRows } = await resolvePrimaryData<TData>(
    config,
    signal
  )

  const withDerived = await computeDerivedValues(
    primaryRows,
    config.columns,
    config.options?.subRowsField
  )
  const { rows, rowSourceErrors } = await enrichRowsWithRowLevelSources(
    withDerived,
    config,
    sourceMap,
    signal
  )

  return { rows, sourceMap, rowSourceErrors }
}

// ─── Hook ─────────────────────────────────────────────────────────────────────

/**
 * Orchestrates config validation, DAG-based API fetching, derived value computation,
 * row-level enrichment, and column building for a given TableConfig.
 *
 * Returns everything DataGrid needs — pass the result to <ConfiguredTable /> or
 * spread it manually onto <DataGrid />.
 */
export function useTableEngine<TData extends GridRow>(
  config: TableConfig
): TableEngineResult<TData> {
  // Validate config once at mount — throws ConfigError before any render/query
  const validationError = React.useMemo(() => {
    try {
      validateConfig(config)
      return null
    } catch (err) {
      return err instanceof Error ? err : new Error(String(err))
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [config.id]) // Only re-validate when id changes (config identity)

  const isFlat = config.mode === "flat"
  const isPaginated = config.mode === "paginated"
  const isInfinite = config.mode === "infinite"
  const isTree = config.mode === "tree"

  // ── Flat + Paginated + Tree: useQuery ───────────────────────────────────
  const flatQuery = useQuery({
    queryKey: [config.id, "engine", config.mode],
    queryFn: ({ signal }): Promise<ResolvedData<TData>> =>
      resolveAll<TData>(config, signal),
    enabled: !validationError && (isFlat || isPaginated || isTree),
    placeholderData: keepPreviousData,
  })

  // ── Infinite: useInfiniteData ───────────────────────────────────────────
  const infiniteQuery = useInfiniteData<TData>({
    queryKey: [config.id, "engine"],
    queryFn: async ({ pageParam, sort, filters }) => {
      // Inject page context into the primary source's params via a special $pageParam binding
      const paginatedConfig: TableConfig = {
        ...config,
        dataSources: config.dataSources.map((s, idx) =>
          idx === 0
            ? {
                ...s,
                params: {
                  ...s.params,
                  page: String(pageParam),
                  _sort: JSON.stringify(sort),
                  _filters: JSON.stringify(filters),
                },
              }
            : s
        ),
      }

      const { rows } = await resolveAll<TData>(paginatedConfig)
      return {
        rows,
        nextPage:
          rows.length >= (config.options?.pageSize ?? 50)
            ? pageParam + 1
            : null,
        total: undefined,
      }
    },
    sortState: [],
    filterState: [],
    enabled: !validationError && isInfinite,
  })

  // ── Row-source errors — derived from query data (populated by resolveAll) ──
  const rowSourceErrors: TableEngineResult<TData>["rowSourceErrors"] =
    flatQuery.data?.rowSourceErrors ?? []

  // ── Column build (memoized) ─────────────────────────────────────────────
  const sourceMap: SourceMap = React.useMemo(() => {
    if (isInfinite) return {}
    return flatQuery.data?.sourceMap ?? {}
  }, [flatQuery.data, isInfinite])

  const { columns, initialColumnVisibility } = React.useMemo(
    () => buildColumns<TData>(config.columns, config.features, sourceMap),
    [config.columns, config.features, sourceMap]
  )

  // ── Derive final rows ────────────────────────────────────────────────────
  const data: TData[] = React.useMemo(() => {
    if (isInfinite) return infiniteQuery.rows as TData[]
    return flatQuery.data?.rows ?? []
  }, [isInfinite, infiniteQuery.rows, flatQuery.data])

  // ── Loading / error state ────────────────────────────────────────────────
  const isLoading = isInfinite ? infiniteQuery.isLoading : flatQuery.isLoading
  const isError = isInfinite
    ? infiniteQuery.isError
    : validationError !== null || flatQuery.isError
  const error: Error | null = isInfinite
    ? (infiniteQuery.error as Error | null)
    : (validationError ?? (flatQuery.error as Error | null))

  return {
    data,
    columns,
    initialColumnVisibility,
    isLoading,
    isError,
    error,
    refetch: isInfinite ? infiniteQuery.refetch : flatQuery.refetch,
    rowSourceErrors,
    // Infinite mode props
    ...(isInfinite
      ? {
          fetchNextPage: infiniteQuery.fetchNextPage,
          hasNextPage: infiniteQuery.hasNextPage,
          isFetchingNextPage: infiniteQuery.isFetchingNextPage,
          total: infiniteQuery.total,
        }
      : {}),
  }
}

